(window.courseContentFiles = window.courseContentFiles || {})["000008/0001"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Въпроси</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: left; transition: background-color 0.3s\">ЕТАПИ НА ЛАБОРАТОРИЯ</h1><p><strong>Лабораторният процес включва следните етапи:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Преданалитичен, аналитичен и постаналитичен етап</span></li><li>Преданалитичен и постаналитичен етап</li><li>Аналитичен и постаналитичен етап</li></ul><p><strong>Най-чести са грешките на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Преданалитичен етап</span></li><li>Аналитичен етап</li><li>Постаналитичен етап</li></ul><p><strong>Аналитичните грешки биват два типа:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Случайни и системни</span></li><li>Случайни и чести</li><li>Системни и чести</li></ul><p><strong>Причини за грешки на преданалитичния етап:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Сгрешен идентификационен номер на пациента</li><li>Недостатъчно количество биологичен материал</li><li>Биологичната проба е взета във вакуета с неподходящ антикоагулант</li></ul></ul><p><strong>Грешки на постаналитичния етап са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Грешка в интерпретацията на лабораторния резултат</span></li><li>Биологичната проба е взета във вакуета с неподходящ антикоагулант</li><li>Недостатъчно количество биологичен материал</li><li>Всички изброени</li></ul><p><strong>Вакуета с антикоагулант/адитив ЕДТА се препоръчва за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хематологичен анализ </span>(<span style=\"color: rgb(0, 176, 80)\">лилавка капачка</span>)</li><li>Биохимичен анализ</li><li>Уринен анализ</li><li>Серологичен анализ</li></ul><p><strong>Вакуета с антикоагулант/адитив Натриев цитрат се използва за изследване на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Параметри на хемостазата</span></li><li>Електролити</li><li>Пълна кръвна картина</li><li>Биохимични параметри</li></ul><p><strong>Серум и плазма се различават по съдържанието на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Плазмени фактори на кръвосъсирването</span></li><li>Липиди</li><li>Електролити</li><li>Кръвни клетки</li></ul><p><strong>Всички от изброените твърдения за серум и плазма са верни, ОСВЕН:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">серумът съдържа коагулационни фактори, а плазмата – не</span></li><li>вакутейнер с жълта или червена капачка служи за получаване на серум, а вакутейнер със зелена капачка – за плазма</li><li>серум и плазма представляват течната съставка на кръвта</li><li>серум и плазма се получават след като пълната кръв се центрофугира</li><li>кръвта се центрофугира задължително 20-30 мин. след вземането й, за да се отдели серум, докато за получаване на плазма кръвта може да се центрофугира веднага</li></ul><p><strong>Каква е разликата между серум и плазма?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Серумът е неразредената, извънклетъчна част на кръвта след завършване на пълна коагулация. Плазмата е съставена от серум и коагулационни фактори.</li><li>Серумът е частта от кръвта, в която липсват коагулационни фактори.</li><li>Плазмата е течната част на кръвта без клетки, която е третирана с антикоагуланти.</li></ul></ul><p><strong>Кой от следните типове проби налага забавяне обработката на пробите преди анализа:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Серумен вакутейнер с гел активатор </span>(<span style=\"color: rgb(0, 176, 80)\">жълта капачка</span>)</li><li>Вакуета с адитив ЕДТА</li><li>Вакуета с адитив Литив хепаринат</li><li>Вакуета с Натриев цитрат</li></ul><p><strong>Причините за лошо направен кръвен размаз могат да бъдат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Продължително съхранение на пробите в EDTA и мръсни предметни стъкла</li><li>Забавяне при приготвянето на размаза, след като капката кръв вече е поставена върху стъклото</li><li>Капка кръв, която е твърде голяма или твърде малка</li><li>Държане на разстилащото стъкло под грешен ъгъл и лоши условия за изсушаване</li></ul></ul><p><strong>Лабораторният контрол в клиничната лаборатория бива:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вътрешен и външен лабораторен контрол</span></li><li>Вътрелабораторен качествен контрол</li><li>Външен контрол</li><li>Нито един от изброените</li></ul><p><strong>Фактори, които повлияват границите на референтния интервал:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени&nbsp;</span></li><ul><li>Пол, възраст</li><li>Бременност</li><li>Раса</li></ul></ul><p><strong>Кой антикоагулант има антигликолитично действие (запазва нивата на глюкозата)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Натриев йодацетат</span></li><li>Heparin</li><li>Цитрат</li><li>Няма верен отговор</li></ul><p><strong>В какъв вакутейнер се взема кръв за изследване на коагулационни параметри?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">син</span></li><li>лилав</li><li>жълт</li><li>зелен</li></ul><p><strong>Кое твърдение относно референтните стойности НЕ е вярно:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">резултат извън референтната област, означава наличие на заболяване</span></li><li>референтните стойности могат да бъдат групови и индивидуални</li><li>референтните стойности могат да зависят от пол, възраст, раса и др.</li><li>5% от здравите лица имат стойности извън референтната област</li></ul><p><strong>Преданалитичния етап на лабораторното изследване НЕ включва?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">интерпретация на резултата</span></li><li>вземане на биологичен материал</li><li>подготовка на пациента</li><li>оформяне на искане за лабораторно изследване</li></ul><p><strong>Кои са типичните преаналитични грешки при вземане на кръв за изследване на хемостаза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени:</span></li><ul><li>Травмиране при венепункция</li><li>Контаминиране с екзогенен антикоагулант</li><li>Недостатъчно количество кръв</li></ul></ul><p><strong>Кои от изброените са задължителни изисквания при подготовка за вземане на кръв?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички са верни:</span></li><ul><li>Почивка 15 мин преди венепункция</li><li>12 часа хранителна пауза</li><li>Преустановяване на алкохола 3 дни по-рано</li></ul></ul><p><strong>Кое от следните трябва да се има предвид при изследване на плазмена проба за коагулационни тестове? Пробата трябва да се провери за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Правилен обем в епруветката</li><li>Наличие на липемия</li><li>Наличие на хемолиза</li></ul></ul><p><strong>Биологична причина за лоша периферна натривка е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Студени аглутинини - еритроцитите се струпват на купове</li><li>Липемия - в натривката се появяват „дупки“ (неоцветени зони)</li><li>Руло (Rouleaux) - еритроцитите се подреждат в колони като монети</li></ul></ul><p><strong>При вземане на венозна кръв, за лабораторни изследвания най-често усложнение на пациента е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">хематом</span></li><li>алергична реакция към дезинфектанта</li><li>тромбоза</li></ul><p><strong>Най-висока амплитуда в циркадните отклонения има при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">желязо</span></li><li>левкоцити</li><li>TSH</li></ul><p><strong>Честа причина за фалшиво повишен LDH (лактат дехидрогеназа) е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемолизирана проба</span></li><li>Чернодробно заболяване</li><li>Лекарствена токсичност</li><li>Застойна сърдечна недостатъчност</li></ul><p><strong>Вътрешният качествен контрол се основава на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Изследване на контролни проби с известни стойности преди изследването на пациентите</span></li><li>Редовно тестване на една и съща пациентска проба в продължение на 20 дни от месеца</li><li>Оценка на резултатите от независима сертифицирана институция</li><li>Двойно тестване на всяко лабораторно измерване</li></ul><p><strong>Какво се случва, ако епруветка за коагулационни изследвания е недостатъчно напълнена?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Резултатите от тестовете, базирани на съсирване, са фалшиво удължени</span></li><li>Пробата се съсирва и е неизползваема</li><li>Пробата се хемолизира и е неизползваема</li><li>Резултатите от хромогенните тестове са фалшиво понижени</li></ul><p><strong>Ако вземате кръв в серия от епруветки, кога в последователността трябва да се напълни епруветката за хемостаза със синя капачка?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Първа или след епруветка без добавки</span></li><li>След епруветка с EDTA или хепарин</li><li>След епруветка със серумен сепаратор</li><li>Последна</li></ul><p><strong>С кои йони се свързва ЕДТА, за да прояви своя антикоагулантен ефект?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Калциеви йони (Ca2+)</span></li></ul><p><strong>Периферното убождане при новородени се прави от:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Петичка</span></li></ul><strong>Кое от изброените е пример за грешка в постаналитичния период на лабораторното изследване?</strong><br><ul><li><span style=\"color: rgb(255, 0, 0)\">Предаване на резултатите на грешен пациент</span></li></ul><p><strong>Серум и плазма се различават по съдържание на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фибриноген</span></li></ul><p><strong>Посочете вярното твърдение относно вземането на кръв за изследване на хемостаза:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">епруветката трябва да е втора, след серумната епруветка </span>(<span style=\"color: rgb(0, 176, 80)\">за да се избегне тъканния фактор</span>)</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"transition: background-color 0.3s\">АНЕМИИ</h1><p><strong>Еритроцитните индекси са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">MCV, MCH, MCHC, RDW</span></li><li>MCV, MCH, RDW, PLT</li><li>MCV, MCH, MCHC, MPV</li><li>WBC, RBC, MCV, MCH</li><li>WBC, RBC, PLT, MCV, MCH</li></ul><p><strong>Съгласно морфологичната класификация на анемиите Желязо-дефицитната анемия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцитна, хипохромна</span></li><li>Макроцитна, хипохромна</li><li>Микроцитна, нормохромна</li><li>Нормоцитна, хипохромна</li></ul><p><strong>Съгласно морфологичната класификация на анемиите В12- дефицитната анемия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Макроцитна анемия</span></li><li>Микроцитна, хипохромна</li><li>Микроцитна, нормохромна</li><li>Нормоцитна, хипохромна</li></ul><p><strong>Съгласно морфологичната класификация на анемиите Фолиево-дефицитната анемия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Макроцитна анемия</span></li><li>Макроцитна, хипохромна</li><li>Микроцитна, хипохромна</li><li>Нормоцитна, нормохромна</li></ul><p><strong>Съгласно морфологичната класификация на анемиите Таласемията е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцитна, хипохромна</span></li><li>Нормоцитна, нормохромна</li><li>Макроцитна, хипохромна</li><li>Нормоцитна, хипохромна</li></ul><p><strong>Анемия, която съгласно морфологичната класификация е микроцитна, хипохромна, но не е Желязодефицитна анемия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Таласемия</span></li><li>Пернициозна анемия</li><li>Сърповидно-клетъчна анемия</li><li>Апласична анемия</li></ul><p><strong>Пернициозната и фолиево-дефицитната анемия са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегалобластни анемии</span></li><li>Микроцитни анемии</li><li>Апластични анемии</li><li>Нормоцитни, нормохромни анемии</li></ul><p><strong>Кой от следните еритроцитни индекси предоставя информация за размера на еритроцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">МCV</span></li><li>RDW</li><li>МСНС</li><li>MCH</li></ul><p><strong>Кой от следните еритроцитни индекси предоставя информация за средното съдържание на хемоглобин в един еритроцит?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">MCH</span></li><li>RDW</li><li>МСНС</li><li>МCV</li></ul><p><strong>Кой от следните еритроцитни индекси предоставя информация за разпределението на еритроцитите по обем:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">RDW</span></li><li>МСНС</li><li>МCV</li><li>MCH</li></ul><p><strong>Терминът макроцитоза се използва в случаите, когато:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">MCV &gt; 100 fl</span></li><li>MCV &lt; 80 fl</li><li>MCHC &gt; 38%</li><li>MCH &gt; 32 pg</li></ul><p><strong>От долу изброените състояние кое води до развитието на пернициозна анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Стомашна резекция</span></li><li>Бременност</li><li>Диета богата на протеини</li><li>Бактериална инфекция</li></ul><p><strong>Нормалните Хемоглобинови нива при здрави възрастни мъже са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">140-180g/l</span></li><li>120-140g/l</li><li>100-150g/l</li><li>160-200g/l</li></ul><p><strong>Нормалната хемоглобинова концентрация при здрави, небременни жени е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">120-160g/l</span></li><li>140-180g/l</li><li>100-150g/l</li><li>160-200g/l</li></ul><p><strong>Коя лабораторна констелация характеризира Желязо-дефицитната анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">↓Hb, ↓Fe, ↑ТЖСК, ↓Ferritin</span></li><li>↓Hb, ↓Fe, ↑ТЖСК, ↑Ferritin</li><li>↓Hb, ↓Fe, ↓ТЖСК, ↓Ferritin</li><li>↓Hb, ↓Fe, ↓ТЖСК, ↑Ferritin</li></ul><p><strong>При пациенти с Желязо-дефицитна анемия има:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Ниски серумни нива на Hepsidin</span></li><li>Нормални серумни нива на Hepsidin</li><li>Високи серумни нива на Hepsidin</li></ul><p><strong>При желязо-дефицитната анемия нивата на хепцидин са?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">понижени</span></li><li>повишени</li><li>нормални</li></ul><p><strong>При пациенти с Желязо-дефицитна анемия разтворимите трансферинови рецептори (sTfR) са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишени</span></li><li>Нормални</li><li>Понижени</li></ul><strong>При суплементация с железни препарати:</strong><br><ul><li><span style=\"color: rgb(255, 0, 0)\">Разтворимите трансферинови рецептори (sTfR) се понижават</span></li><li>Разтворимите трансферинови рецептори (sTfR) се повишават</li><li>Разтворимите трансферинови рецептори (sTfR) не се променят</li></ul><p><strong>Риск от спонтанни кръвоизливи има, когато броят на тромбоцитите е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&lt; 30х10<sup>9</sup>/l</span></li><li>&lt; 100х10<sup>9</sup>/l</li><li>&lt; 50х10<sup>9</sup>/l</li><li>&lt; 140х10<sup>9</sup>/l</li></ul><p><strong>По време на хирургични интервенции и травми съществува риск от кървене ако:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Броят на Thr &lt; 50х10<sup>9</sup>/l</span></li><li>Броят на Thr &lt; 100х10<sup>9</sup>/l</li><li>Броят на Thr &lt; 30х10<sup>9</sup>/l</li><li>Броят на Thr &lt; 140х10<sup>9</sup>/l</li></ul><p><strong>Лабораторното обяснение за RDW &gt; 14% е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Вариация в размера на еритроцитите</li><li>Анизоцитоза</li><li>Смесена популация от еритроцити</li></ul></ul><p><strong>Еритроцитите с големина &gt; 8,1 µ се наричат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Макроцити</span></li><li>Микроцити</li><li>Нормоцити</li><li>Шизоцити</li></ul><p><strong>Еритроцити с големина &lt; 6 µ се наричат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцити</span></li><li>Нормоцити</li><li>Макроцити</li><li>Дакриоцити</li></ul><p><strong>Нормалната биконкавна форма на еритроцита НЕ се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Сфероцит</span></li><li>Микроцит</li><li>Нормоцит</li><li>Макроцит</li></ul><p><strong>Повишен брой ретикулоцити (ретикулоцитоза) се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемолитични анемии</span></li><li>Желязо-дефицитна анемия</li><li>Апластична анемия</li><li>Нелекувана Пернициозна анемия</li></ul><p><strong>При Хемолитичните анемии е налице:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Ексцесивна деструкция на еритроцити</span></li><li>Дефицит на Вит В12</li><li>Дефицит на фолиева киселина</li><li>Кръвозагуба</li></ul><p><strong>Фактори, повлияващи физиологично броя на еритроцитите в кръвта са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">пол, възраст, надморска височина</span></li><li>постоянна употреба на алкохол</li><li>дълговременно приемане на аналгин</li><li>неспазване на стандартна процедура за вземане на кръв за хематологично изследване</li></ul><p><strong>От ПКК на пациент с Таласемия минор се наблюдава:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">↓Hb,↑ Ery, ↓MCV, ↓MCH, ↑Fe, N/↓ТЖСК</span></li><li>↓Hb,↑ Ery, ↑MCV, ↑MCH, ↓Fe, ↑ТЖСК</li><li>↓Hb,↓ Ery, ↑MCV, ↑MCH, ↓Fe, ↑ТЖСК</li><li>↓Hb,↑ Ery, ↑MCV, ↓MCH, ↑Fe, N/↓ТЖСК</li></ul><p><strong>Резултатите за Хемоглобин се изразяват в:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">g/l</span></li><li>mg/dl</li><li>%</li><li>fl</li></ul><p><strong>Ретикулоцитите не се откриват чрез обичайното оцветяване по Романовски-Гимза, а посредством специално суправитално обагряне, което най-често се извършва с 1% разтвор на брилянткрезилблау. Така се доказват вариращи по количество остатъци от ………………….. под формата на зърнисто-мрежеста субстанция, нар. substantia granulofilamentosa.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">РНК</span></li><li>Рибозоми</li><li>ДНК</li><li>Всички изброени</li></ul><p><strong>Kой от изброените параметри дава количествена оценка за степента на анизоцитоза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">RDW</span></li><li>MCV</li><li>MCHC</li><li>HbA1C</li></ul><p><strong>При какви стойности на хемоглобина анемията се определя като лека?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Hb &gt; 95 g/L</span></li><li>Hb = 80÷94 g/L</li><li>Hb = 65÷79 g/L</li><li>Hb &lt; 65 g/L</li></ul><p><strong>При какви стойности на хемоглобина, анемията е животозастрашаваща?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Hb &lt; 65 g/L</span></li><li>Hb &gt; 95 g/L</li><li>Hb = 80-96 g/L</li><li>Hb = 60-79 g/L</li></ul><p><strong>Според патофизиологичната класификация, при кой тип анемии се наблюдава намалена преживяемост на еритроцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Анемии, свързани с хемолиза</span></li><li>Анемии при хронични заболявания</li><li>Анемия на Фанкони</li><li>Желязодефицитна анемия</li></ul><p><strong>Какво представлява индексът MCH?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Средно съдържание на хемоглобин в един еритроцит</span></li><li>Среден обем на еритроцита</li><li>Средна концентрация на хемоглобин в еритроцитната маса</li><li>Степен на вариация в обема на еритроцитите</li></ul><p><strong>При кое заболяване се наблюдава намаление на MCV (микроцитоза)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">При таласемии</span></li><li>При дефицит на фолиева киселина и витамин В12</li><li>При инфекциозни заболявания</li><li>При апластична анемия</li></ul><p><strong>Абнормно малки еритроцити с MCV &lt; 80fl и диаметър под 7.0 µm се наричат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцитоза</span></li><li>Макроцитоза</li><li>Анизоцитоза</li><li>Пойкилоцитоза</li></ul><p><strong>Кое от следните може да се открие единствено чрез изследване на периферна кръвна натривка?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пойкилоцитоза</span></li><li>Микроцитоза</li><li>Анизоцитоза</li><li>Хипохромия</li></ul><p><strong>Увеличението на общия брой левкоцити над нормата се нарича:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Левкоцитоза</span></li><li>Левкемия</li><li>Левкопения</li><li>Левкофилия</li><li>Лимфоцитоза</li></ul><p><strong>Абсолютна лимфоцитоза се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Инфекциозна мононуклеоза</span></li><li>Трихинелоза</li><li>Алергии</li><li>Бактериални инфекции</li></ul><p><strong>Бременност, физическо натоварване, стрес, прегряване, остра бактериална инфекция, миокарден инфаркт, изгаряне, хемолиза и интоксикация са причини за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Неутрофилия</span></li><li>Еозинофилия</li><li>Лимфоцитоза</li><li>Неутропения</li></ul><p><strong>Кое от следните НЕ е причина за еозинофилия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Стерoидна терапия</span></li><li>Екзема</li><li>Анкилостомиаза</li><li>Лимфом на Ходжкин</li></ul><p><strong>Увеличението на метамиелоцити, миелоцити и промиелоцити може да се нарече:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Оливяване наляво</span></li><li>Левкоцитопения</li><li>Оливяване надясно </li><li>Аномалия на Pelger-Huet</li></ul><p><strong>Какви са референтните стойности на Hb при хематологичен анализ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">120 - 180 g/L</span></li><li>80 - 100 g/L</li><li>60 - 80 g/L</li><li>200 g/L</li></ul><p><strong>Към анемиите с нарушена еритропоеза НЕ спада:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Анемия при хемоглобинопатии</span></li><li>Дефицит на витамин B12</li><li>Анемия при бъбречни заболявания (<span style=\"color: rgb(0, 176, 80)\">намален синтез на еритропоетин</span>)</li><li>Анемия на Fanconi (<p><span style=\"color: rgb(0, 176, 80)\">Вродена апластична анемия</span>)</p></li></ul><p><strong>Намаление на Hb и/или RBC и Hct под долна референтна граница за здрави лица, задължително се съобразява с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пол, възраст, раса и др.</span></li><li>Само пол</li><li>Само възраст и раса</li><li>Единствено с фактори на околната среда</li></ul><p><strong>При кои състояния броят на ретикулоцитите в периферната кръв се увеличава?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">След кръвозагуба</span> (<span style=\"color: rgb(0, 176, 80)\">също и при хемолиза</span>)</li><li>Алкохолизъм</li><li>Неефективна еритропоеза</li><li>Всички са верни</li></ul><p><strong>При кой тип анемия има намалени стойности на MCV и повишено RDW?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Желязодефицитна анемия</span></li><li>Сърповидно-клетъчна анемия</li><li>При бъбречно заболяване</li><li>Апластична анемия</li></ul><p><strong>Към мегалобластните анемии се отнася:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пернициозната анемия</span> (<span style=\"color: rgb(0, 176, 80)\">нарушен синтез на intrinsic factor от париетални клетки → намалено усвояване на витамин B12 от тънките черва</span>)</li><li>Таласемия майор</li><li>Желязодефицитната анемия</li><li>Всички</li></ul><p><strong>Кое е белег на узряване на прекурсорите на кръвните клетки в костния мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Уплътняване и кондензиране на хроматина</span></li><li>Асинхронно матуриране на ядро и цитоплазма</li><li>Увеличаване на ядрено/цитоплазмения индекс</li><li>Увеличаване на размера на прекурсорните клетки</li></ul><p><strong>Коя е последната пролиферираща клетка в еритроидния ред?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Полихроматофилен еритробласт</span></li><li>Базофилен еритробласт</li><li>Оксифилен еритробласт</li><li>Ретикулоцит</li></ul><p><strong>Какво е съотношението на зрели към незрели клетки в костния мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Зрели &gt; Незрели</span> (<span style=\"color: rgb(0, 176, 80)\">костният мозък е и депо</span>)</li><li>Зрели &lt; Незрели</li><li>Зрели = Незрели</li></ul><p><strong>Кой от изброените не е механизъм на възникване на ЖДА?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">повишена резорбция на желязо</span></li><li>намален внос на желязо с храната</li><li>повишени нужди от желязо</li><li>повишена загуба на желязо</li></ul><p><strong>Кои показатели са верни при мегалобластна анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">намалени Ret </span>(<span style=\"color: rgb(0, 176, 80)\">поради&nbsp;н</span><span style=\"color: rgb(0, 176, 80)\">еекфективна еритропоеза</span>)</li><li>увеличени Hb, RBC, Hct</li><li>намалени MCH и RDV</li><li>увеличени WBC и PLT</li></ul><p><strong>Кой от изброените патофизиологични механизми на анемиите при ХЗ е грешен?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">увеличен синтез на еритропоетин</span> (<span style=\"color: rgb(0, 176, 80)\">понижен</span>)</li><li>нарушена реутилизация на желязото</li><li>потиснат отговор на к.м. клетки към ЕРО</li><li>скъсен живот на еритроцитите</li></ul><p><strong>Посочете вярното твърдение за узряването на клетките в костния мозък.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">всички са верни</span></li><ul><li>с узряването кръвните клетки стават по-малки</li><li>хроматинът се уплътнява и кондензира</li><li>изчезват нуклеолите</li></ul></ul><p><strong>Кой от изброените показатели ще е нисък при анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">хемоглобин</span></li><li>неутрофили</li><li>INR</li><li>aPPT</li></ul><p><strong>Хиперсегментация на ядрата на неутрофилните гранулоцити е характерна находка при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">мегалобластната анемия</span></li><li>желязо-дефицитната анемия</li><li>хетерозиготната β таласемия</li><li>микросфероцитоза</li></ul><p><strong>Абсолютна еритроцитоза се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">полицитемия вера</span></li><li>анемия</li><li>хиперхидратация</li><li>дехидратация</li></ul><p><strong>Количеството на резервното желязо в депата се оценява най-добре чрез:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">серумен феритин</span></li><li>миоглобин</li><li>серумен трансферин</li><li>хемоглобин</li></ul><p><strong>Мъж с астено-адинамичен синдром, намалени Hb, феритин, еритроцити...... повишен ТЖСК. Най-вероятната диагноза е?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Желязодефицитна анемия</span></li><li>бета-таласемична анемия</li><li>мегалобластна анемия</li><li>анемия при ХЗ</li></ul><p><strong>Повишеният брой ретикулоцити в кръвта е белег за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">усилена еритропоеза</span></li><li>бактериално възпаление</li><li>алергична реакция на организма</li></ul><p><strong>Кое твърдение е вярно:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">СУЕ отразява суспензионната стабилност на Er в кръвта</span></li><li>СУЕ е лабораторен тест, характеризиращ се с висока диагностична специфичност</li><li>СУЕ има малко източници на грешки при провеждане на анализа</li></ul><p><strong>Кое твърдение НЕ е вярно.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Трансферинът отразява резервите на организма от желязо</span></li><li>Трансферинът може да бъде определен и като ТЖСК</li><li>Трансферинът е индивидуален белтък</li><li>Трансферинът е транспортен белтък на желязото</li></ul><p><strong>Кой от изброените е отрицателен острофазов белтък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">албумин</span></li><li>С-реактивен протеин</li><li>фибриноген</li><li>хаптоглобин</li></ul><p><strong>Пациент има анемия, понижени еритроцитни индекси и таргетни клетки в периферната кръвна картина. Серумното желязо е нормално, а електрофорезата показва повишен HbF и HbA2. Каква е възможната диагноза?:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Бета таласемия</span></li><li>Мегалобластна анемия</li><li>Сидеробластна анемия</li><li>Анемия при хронично възпаление</li></ul><p><strong>40-годишна жена съобщава, че се чувства постоянно изморена. При прегледа отчитате тахикардия и бледост. Назначавате ПКК, която показва следното: Hgb 100 g/L, MCV 75. Броят на ретикулоцитите не е повишен. Кое от следните е най-вероятно?:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Желязодефицитна анемия</span></li><li>Мегалобластна анемия, вероятно поради дефицит на фолати</li><li>Мегалобластна анемия, вероятно поради дефицит на витамин В12</li><li>Хемолитична анемия</li></ul><p><strong>При пациент с нормоцитна нормохромна анемия, кое от следните е най-ранният лабораторен признак, показващ железен дефицит?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Понижен серумен феритин и изчерпване на депата на желязо в костния мозък</span></li><li>Понижено серумно желязо и повишен серумен трансферин</li><li>Понижен серумен трансферин и повишена сатурация на трансферин</li><li>Повишен серумен трансферин и понижена сатурация на трансферин</li></ul><p><strong>RDW измерва:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вариацията в размера на еритроцитите</span></li><li>Средната концентрация на хемоглобин във всеки еритроцит</li><li>Общия брой на еритроцитите</li><li>Процента от обема на кръвта, съставен от еритроцити</li></ul><p><strong>Морфологичните характеристики на еритроцитите при бета-таласемия най-вероятно включват:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцитни клетки, хипохромни клетки, таргетни клетки</span></li><li>Макроцитни клетки, овалоцити, таргетни клетки</li><li>Микроцитни клетки, сърповидни клетки</li><li>Макроцитни клетки, хипохромни клетки, таргетни клетки</li></ul><p><strong>52-годишна жена страда от остро настъпила нормоцитна, нормохромна анемия, хемоглобинурия, хемосидеринурия и жълтеница, придружени от понижен серумен хаптоглобин. Коя е най-вероятната причина за тези находки?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемолиза</span></li><li>Железен дефицит</li><li>Неадекватна продукция на еритроцити</li><li>Кръвоизлив</li></ul><p><strong>Причините за поява на микроцитни еритроцити включват кое от следните?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">α-Таласемия</span></li><li>Алкохол (<span style=\"color: rgb(0, 176, 80)\">причинява макроцитоза</span>)</li><li>Бъбречно заболяване</li><li>Повишен брой ретикулоцити</li></ul><p><strong>Сфероцитите в кръвната натривка са характеристика на кое от следните?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Автоимунна хемолитична анемия</span></li><li>Таласемия майор</li><li>Ретикулоцитоза</li><li>Дефицит на глюкозо-6-фосфат дехидрогеназа (G6PD)</li></ul><p><strong>Кое от следните е характеристика на хронична екстравазална хемолитична анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Жлъчни камъни</span></li><li>Повишен серумен конюгиран билирубин (<span style=\"color: rgb(0, 176, 80)\">повишен е неконюгираният</span>)</li><li>Нисък брой ретикулоцити</li><li>Хипоцелуларен костен мозък</li></ul><p><strong>Повишената полихромазия в периферната кръвна натривка може да показва кое от следните?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишен относителен брой на ретикулоцитите</span></li><li>Прекалено оцветяване на предметното стъкло</li><li>Намалено производство на еритроцити</li><li>Нищо конкретно</li></ul><p><strong>18-годишно момиче от Швеция се представя с жълтеница и анемия. Лабораторните изследвания показват значително намален среден обем на еритроцитите (MCV), повишена средна концентрация на хемоглобин в еритроцитите (MCHC) и повишена осмотична резистентност на еритроцитите. Еритроцитите в периферната кръвна натривка най-вероятно ще бъдат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Сфероцити</span></li><li>Шизоцити</li><li>Пойкилоцити</li><li>Хипохромни микроцитни еритроцити</li></ul><p><strong>Терминът хромазия се отнася до:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Какъв е цветът на еритроцитите</span> (<span style=\"color: rgb(0, 176, 80)\">степента на наситеност с хемоглобин</span>)</li><li>Колко големи са червените кръвни клетки</li><li>Колко широко разположени са еритроцитите</li><li>Колко хемоглобин има в еритроцитите </li><li>Възрастта на еритроцитите</li></ul><p><strong>60-годишен мъж има хемоглобин 90 g/L. Той има и следните лабораторни резултати: нормален MCV; повишен LDH; понижен хаптоглобин. Кое от следните е най-вероятно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемолитична анемия</span></li><li>Желязодефицитна анемия</li><li>Мегалобластна анемия</li></ul><p><strong>70-годишен пациент с анамнеза за тежка анемия, тромбоцитопения и неутропения е насочен към хематолог. Допълнителните изследвания разкриват значително намаляване на всички хемопоетични предшественици в костния мозък без наличие на дисплазия. В периферната кръв се наблюдава панцитопения и силно понижен хемоглобин. Еритроцитните индекси и морфологията на еритроцитите са нормални. Тези резултати от изследванията и клиничната картина са съвместими с кое заболяване?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Апластична анемия</span></li><li>Анемия при хронични заболявания</li><li>Таласемия</li><li>Желязодефицитна анемия</li></ul><p><strong>RDW не е повишен при пациент, чиято периферна кръвна натривка за морфология на еритроцитите се описва като:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пойкилоцитоза</span></li><li><p>Микроцитоза</p><br></li><li>Анизоцитоза</li><li>Макроцитоза </li></ul><p><strong>При кой тип анемия има намалени стойности на MCV и повишено RDW?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Сърповидно клетъчна анемия</span> (<span style=\"color: rgb(0, 176, 80)\">ддз защо микроцитоза</span>)</li><li>При бъбречно заболяване </li><li>Апластична анемия</li><li>Ретикулоцитоза</li></ul><p><strong>Лабораторните находки при анемия, дължаща се на хронични възпаления, инфекции и тумори, включват:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Понижен Hb; понижени RBC и Hct; понижено Fe; понижен TIBC; повишен феритин</span></li></ul><p><strong>Към отрицателните острофазови белтъци принадлежи:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Трансферин</span></li></ul><p><strong>Посочете пример за вродена хемолитична анемия ….</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1. Ензимни дефекти – Г6ФДХ, ПК</span></li><li><span style=\"color: rgb(255, 0, 0)\">2. Мембранни дефекти – сфероцитоза</span></li><li><span style=\"color: rgb(255, 0, 0)\">3. Хемоглобинопатии – Таласемии</span></li></ul><p><strong>Посочете пример за придобита хемолитична анемия ….</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1. Неимунни – Инфекции / малария /; физични и химични фактори, травми</span></li><li><span style=\"color: rgb(255, 0, 0)\">2. Имунни – автоимунни/ топлинни и студови АТ ; хемолитичина болест на новороденото, кръвопреливания</span></li></ul><p><strong>Увеличени стойности на MCV се наблюдават при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегалобластни анемии</span></li></ul><p><strong>В периферната кръв на здрави възрастни пациенти НЕ се наблюдава:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Еритробласти</span></li></ul><p><strong>С понятието пойкилоцитоза се означава:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Промяна във формата на Еру</span></li></ul><p><strong>За болен с пернициозна анемия са верни всички твърдения, БЕЗ:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Анизомикроцитоза</span> (<span style=\"color: rgb(0, 176, 80)\">Анизо-микро-цитоза се наблюдава при ЖДА</span>)</li></ul><p><strong>Хемолитичните анемии са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Нормоцитни, нормохромни</span></li></ul><p><strong>Мъж на 57 г. с Hb 85 и MCV 104 fl. Кой тест бихте назначили, за да поставите диагноза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Витамин В12 и фолиева киселина </span>(<span style=\"color: rgb(0, 176, 80)\">MCV &gt; 100 fl</span>)</li></ul><p><strong>Кой от изброените параметри се понижава при хемолитична анемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хаптоглобин</span> (<span style=\"color: rgb(0, 176, 80)\">При хемолитична анемия хаптоглобинът се свързва със свободния хемоглобин в стабилни комплекси, за да го неутрализира, и по този начин се изчерпва.</span>)</li></ul><p><strong>RDW (Red blood cell Distribution Width) – определение и референтни граници:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Ширина на разпределение на RBC по обем; РГ: 11.5% ÷ 14.5%</span></li></ul><p><strong>Хемолитична анемия - определение:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Декомпенсирана хемолиза, при която количеството на разрушените еритроцити надвишава произведените компенсаторно еритроидни клетки в к.м.</span></li></ul><p><strong>С какъв метод на оцветяване може да съдим за количеството на РНК в ретикулоцита и съответно за неговата степен на матурация?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Витално оцветяване</span></li></ul><p><strong>Каква е вероятната диагноза на 60-годишен пациент с общо намаление на показателите в кръвната картина?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Желязодефицитна анемия</span></li></ul><p><strong>Какви са референтните стойности за броя на еритроцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">3.7 – 5.3 x 10<sup>12</sup>/L</span></li></ul><p><strong>Каква е основната биологична функция на протеина феритин?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Складиране на желязото в организма</span></li></ul><p><strong>Пациент има следните резултати от периферна кръв: MCV 117 fL, MCH 37 pg, MCHC 320 g/L, 3+ овални макроцити, хиперсегментирани неутрофили. Кое от следните състояния бихте подозирали?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегалобластна анемия</span> (<span style=\"color: rgb(255, 0, 0)\">хиперсегментирани неутрофили!</span>)</li></ul><p><strong>60-годишен мъж има хемоглобин 90 g/L. Той има и следните лабораторни резултати: нормално MCV; повишено LDH; понижен хаптоглобин. Кое от следните е най-вероятно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемолитична анемия</span></li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: left; transition: background-color 0.3s\">WBC</h1><p><strong>Левкоцитите в циркулираща кръв на здрав човек се разделят на следните групи:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Неутрофили, Еозинофили, Базофили, Моноцити, Лимфоцити</span></li><li>Лимфоцити, Неутрофили, Еозинофили, Моноцити, Лимфобласти</li><li>Миелобласти, Неутрофили, Еозинофили, Моноцити, Лимфобласти</li><li>Неутрофили, Еозинофили, Базофили, Монобласти, Лимфоцити</li><li>Неутрофили, Еозинофили, Базофили, Еритроцити, Лимфоцити</li></ul><p><strong>Увеличението на белите кръвни клетки над горната референтна граница за здрави се нарича:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Левкоцитоза</span></li><li>Неутрофилия</li><li>Моноцитоза</li><li>Лимфоцитоза</li><li>Левкопения</li></ul><p><strong>Какъв процент е целуларитетът на костния мозък при възрастни?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">80-30%</span></li><li>50-20%</li><li>90-50%</li><li>100-75%</li></ul><p><strong>Левкемоидна реакция с неутрофилия може да се дължи на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Кръвоизлив</li><li>Сепсис</li><li>Неопластични заболявания</li></ul></ul><p><strong>Физиологични състояния, при които се наблюдава Неутрофилия са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Бременност</li><li>Физически усилия</li><li>Новородени</li><li>Емоционален стрес</li></ul></ul><p><strong>Посочете места за аспириране, които са подходящи само при деца под 1 година:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Tibia</span></li><li>Sternum</li><li>Spina iliaca posterior superior</li><li>Spina iliaca anterior superior</li></ul><p><strong>Най-честата причина за Неутрофилия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра бактериална инфекция</span></li><li>Остра вирусна инфекция</li><li>Алергична реакция</li><li>Инфекции с паразити</li><li>Всички изброени</li></ul><p><strong>Намалението на Неутрофилите под долната референтна граница за здрави се нарича:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Неутропения</span></li><li>Неутрофилия</li><li>Агранулоцитоза</li><li>Неутроцитоза</li><li>Липсва верен отговор</li></ul><p><strong>Състояния и заболявания, при които се наблюдава Еозинофилия са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">А + Б</span></li><li>Алергични реакции</li><li>Инфекции с паразити</li><li>Бактериални инфекции</li><li>А + В</li></ul><p><strong>Еозинофилия с най-високи стойности се наблюдава при пациенти с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Трихинелоза</span></li><li>Сепсис</li><li>Бактериален ендокардит</li><li>Инфаркт на миокарда</li><li>Лобарна пневмония</li></ul><p><strong>Най-малобройната група гранулоцити в периферната кръв на здрави е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Базофили</span></li><li>Еозинофили</li><li>Неутрофили</li><li>Моноцити</li><li>Лимфоцити</li></ul><p><strong>Абсолютна неутрофилия се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Апендицит</span></li><li>Паразитни инвазии</li><li>Вирусни инфекции</li><li>Инфекциозна мононуклеоза</li></ul><p><strong>Хиперсегментирани неутрофили често се отбелязват при следното състояние:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пернициозна анемия</span></li><li>Желязодефицитна анемия</li><li>Остра лимфна левкемия</li><li>Таласемия</li></ul><p><strong>Неутрофилия с повече от 5% пръчкоядрени неутрофили се нарича:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Олевяване</span></li><li>Хиперсегментация</li><li>Агранулоцитоза</li><li>Токсични гранулации</li></ul><p><strong>Кое от следните НЕ е причина за неутрофилна левкоцитоза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Астма </span></li><li>Миокарден инфаркт</li><li>Травма</li><li>Кортикостероидна терапия</li></ul><p><strong>Най-голям процент от всички бели кръвни клетки при здрави възрастни пациенти се пада на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Неутрофили&nbsp;</span><p>(<span style=\"color: rgb(0, 176, 80)\">42-77%</span>)</p></li><li>Еозинофили</li><li>Базофили</li><li>Моноцити</li><li>Лимфоцити</li></ul><p><strong>В сравнение с възрасните пациенти, при здрави деца от 4-5 месечна до 4-5 годишна възраст, най-висок е процентът на коя от изброените групи бели кръвни клетки?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лимфоцити</span></li><li>Еозинофили</li><li>Базофили</li><li>Неутрофили</li><li>Моноцити</li></ul><p><strong>Колко дълго престояват гранулоцитите в кръвта?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">3-12 ч.</span></li><li>15-20 ч.</li><li>30-120 мин.</li><li>2-3 дни</li></ul><p><strong>При олевяване („left shift“), първоначално се увеличава % на коя от по-долу изброените клетки?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пръчкоядрен неутрофил</span></li><li>Сегментоядрен неутрофил</li><li>Миелоцит</li><li>Миелобласт</li><li>Лимфоцит</li></ul><p><strong>Появата на неутрофили с повече от 5 сегмента на ядрото, в 5 или повече % от сегментоядрените неутрофили се означава с термина хиперсегментация и се наблюдава често при пациенти с<strong>:</strong></strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пернициозна анемия</span></li><li>Желязодефицитна анемия</li><li>Апластична анемия</li><li>Остра левкемия</li><li>Хронична миелогенна левкемия</li></ul><p><strong>При аномалията на Pelger-Huët неутрофилните гранулоцити имат:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хипосегментирани ядра</span></li><li>Хиперсегментирани ядра</li><li>Ядра с нормален брой сегменти → 2-5</li><li>А+Б</li><li>А+В</li></ul><p><strong>В периферната кръв на пациенти с Инфекциозна мононуклеоза се установява:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лимфоцитоза с морфологични промени в лимфоцитите</span></li><li>Левкоцитоза с моноцитоза</li><li>Левкоцитоза с неутрофилия</li><li>Левкоцитоза с еозинофилия</li><li>Левкоцитоза с базофилия</li></ul><p><strong>Реактивни лимфоцити се наблюдават при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Инфекциозна мононуклеоза</span></li><li>Мегалобластна анемия</li><li>Остра миелоидна левкемия</li><li>Остра лимфобластна левкемия</li><li>Таласемия</li></ul><p><strong>Абсолютната или относителната лимфоцитоза е характерна за пациенти с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вирусни инфекции</span></li><li>Бактериални инфекции</li><li>Алергични реакции</li><li>Паразитози</li><li>Колагенози</li></ul><p><strong>Плазматичните клетки са краен стадий в съзряването на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">В-лимфоцити</span></li><li>Т-лимфоцити</li><li>NК-клетки</li><li>Неутрофили</li><li>Моноцити</li></ul><p><strong>Резултатът от диференциалното броене на левкоцитите се изразява посредством два различни типа стойности – относителни и абсолютни. С предимство за клиничната интерпретация трябва да се използват:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Абсолютните стойности</span></li><li>Относителните</li><li>И двата вида стойности</li><li>Най-голямо значение има общият брой на левкоцитите</li></ul><p><strong>Увеличеният брой неутрофили може да бъде резултат от мобилизирането на пристенния пул на тези клетки, а това лесно се провокира от:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Стрес</li><li>Физическа активност</li><li>Хранене</li></ul></ul><p><strong>При кое от следните състояния може да се наблюдава токсична гранулация в цитоплазмата на неутрофилите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Сепсис</li><li>Тежко протичащи остри инфекции</li><li>Злокачествени тумори</li><li>Интоксикации</li></ul></ul><p><strong>При визуално-микроскопско класифициране на левкоцитите се откриват и пръчкоядрени неутрофили. Какъв е техният процент при здрави пациенти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">0-6%</span></li><li>1-2%</li><li>5-10%</li><li>0-1%</li><li>0-10%</li></ul><p><strong>Хроничните инфекции като туберкулоза и колагенози могат да се появят с какво?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Моноцитоза&nbsp;</span><p>(<span style=\"color: rgb(0, 176, 80)\">например при туберкулоза моноцитите се превръщат в макрофаги и участват в образуването на грануломи, при колагено ддз защо</span>)</p></li><li>Лимфоцитоза</li><li>Неутрофилия</li><li>Еозинофилия</li></ul><p><strong>За колко време циркулират в кръвта гранулоцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">4 до 8 часа</span></li><li>4 до 5 дни</li><li>10 до 20 часа</li><li>24 до 48 часа</li></ul><p><strong>Какво е процентното количество на лимфоцитите при здраво новородено?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">30%</span></li><li>50%</li><li>60%</li><li>25%</li></ul><p><strong>Посочете кой е характерният белег при аномалията на Alder-Reilly:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Големи азурофилни гранули в цитоплазмата на неутрофили, лимфоцити и моноцити</span></li><li>Гигантски лизозомни включвания в цитоплазмата, (<p>миелопероксидазо +), различно оцветени</p></li><li>Телца на Döhle</li></ul><strong>Коя е първата разграничима клетка в реда на образуване на тромбоцитите?</strong><br><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегакариобласт</span></li><li>Хемоцитобласт</li><li>Промегакариоцит</li><li>Мегакариоцит</li></ul><p><strong>Посочете за коя клетка от реда на образуване на тромбоцитите се отнася характеристиката „Размерът на клетката е 30-60μm,ядрото е полиплоидно (брой: 2-4); кръгла, овална форма или леко вгънато, с тъмно-виолетов цвят; хроматин: грубо мрежест; нуклеоли: полуразрушени; Цитоплазма: обилна, с голям брой азурофилни гранули, които са разположени предимно около ядрото; гранулите са 3 типа: плътни, алфа- и лизозомни“?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Промегакариоцит</span></li><li>Хемоцитобласт</li><li>Мегакариобласт</li><li>Мегакариоцит</li></ul><p><strong>Колко процента съставляват неутрофилите в кръвта?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">40-72%</span></li><li>2-9,5%</li><li>0,5-5,5%</li><li>0,01-1,75%</li></ul><p><strong>Коя клетка от белия кръвен ред е най-многобройна в костния мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пръчкоядреният неутрофил</span></li><li><p>Сегментоядреният неутрофил (<span style=\"color: rgb(0, 176, 80)\">най-многобройна в циркулация</span>)</p><br></li><li>Еозинофилът</li><li>Базофилът</li></ul><p><strong>Левкоцитите с най-голям размер са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">моноцити</span></li><li>неутрофили</li><li>еозинофили</li><li>лимфоцити</li></ul><p><strong>Кое от процентните съотношения на левкоцитите в кръвта е написано вярно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">лимфоцити - 20.0-44.0</span></li><li>неутрофили - 2.0-9,5</li><li>моноцити - 42.0-77.0</li><li>еозинофили - 0.01-1.75</li></ul><p><strong>Посочете грешното твърдение: Причини за левкемоидна реакция са...</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">СПИН</span></li><li>тежки хеморагии, остра хемолиза</li><li>бактериални инфекции</li><li>малигнени заболявания</li></ul><p><strong>Кои клетки е нормално да са увеличени през периода 3-5г.?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">лимфоцити</span></li><li>еозинофилни левкоцити</li><li>базофили</li><li>макрофаги</li></ul><p><strong>Кой от показателите се увеличава при остра стрептококова инфекция?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">неутрофили</span></li><li>еозинофили</li><li>хемоглобин</li><li>INR</li></ul><p><strong>Кой от следните показатели е увеличен при паразитоза или алергична реакция?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">еозинофили</span></li><li>неутрофили</li><li>хемоглобин</li><li>базофили</li></ul><p><strong>Всички твърдения се верни с ИЗКЛЮЧЕНИЕ на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">при новородени в ДКК се наблюдава преобладаване на лимфоцитите&nbsp;</span><p>(<span style=\"color: rgb(0, 176, 80)\">в началото има неутрофилия, после на ~5-ти ден падат неутрофилите и се качват лимфоцитите и после пак се обръщат на ~5 годишна възраст</span>)</p></li><li>при новородени може да има олевяване</li><li>при новородени общият брой левкоцити е по-висок отколкото при възрастни</li><li>при новородени в ДКК се наблюдава преобладаване на неутрофилните гранулоцити</li></ul><p><strong>На какво микроскопско увеличение се прави оценка на мегакариопоезата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">х400</span></li><li>х100</li><li>х1000</li></ul><p><strong>Неутрофилните метамиелоцити най-добре се различават от неутрофилните пръчкоядрени клетки по какъв критерий?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Форма на ядрото</span> </li><li>Цвят на цитоплазмата</li><li>Цвят на гранулите</li><li>Количество на цитоплазмата</li></ul><p><strong>30-годишна жена има брой на левкоцитите в периферната кръв 10,500/μl с диференциално броене: 61% сегментоядрени, 3% пръчкоядрени, 15% лимфоцити, 8% моноцити и 13% еозинофили. Тези находки обикновено могат да бъдат свързани с всяко от следните, С ИЗКЛЮЧЕНИЕТО НА:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Терапия с кортикостероиди</span> (<span style=\"color: rgb(0, 176, 80)\">пациентката има еозинофилия, а при кортикостероиди настъпва еозинопения</span>)</li><li>Хронична миелогенна левкемия</li><li>Екзогенна астма</li><li>Хиперсензитивен пневмонит</li><li>Инфекция с Ascaris lumbricoides </li></ul><p><strong>Най-честите причини за моноцитоза са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Възстановяване от неутропения и хронични инфекции</span></li><li>Истинска полицитеми</li><li>Свръхчувствителност и алергични реакции</li><li>CML и миелоидна метаплазия</li></ul><p><strong>Кои състояния са индикация за провеждане на изследване на костен мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></li><ul><li>Съмнение за левкемия</li><li>Метастази в костен мозък при нехематологични злокачествени заболявания</li><li>Невробластом</li></ul></ul><p><strong>Неутрофилията е характерна находка при:</strong></p><ul><li><p><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span></p><br></li><ul><li>Бактериална инфекция</li><li>Тъканна некроза</li><li>При КС лечение</li></ul></ul><p><strong>Лимфоцитозата е характерна находка при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вирусни инфекции</span></li><li><p>При КС лечение</p><br></li><li><p>Болест на Ходжкин</p></li><li>Всичко изброено</li></ul><p><strong>Еозинофилията е характерна находка за:</strong></p><ul><li>Всичко изброено</li><ul><li>Алергични заболявания</li><li>Паразитоза</li><li>Херпетиформен дерматит</li></ul></ul><p><strong>Моноцитозата е характерна находка при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><p>Всичко изброено</p><br></span></li><ul><li>Хронични инфекции</li><li>Реактивната фаза на бактериални инфекции</li><li>ХМЛ</li></ul></ul><p><strong>При възрастни в ДКК преобладават:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Сегментоядрени неутрофилни гранулоцити</span></li><li>Лимфоцити</li><li>Пръчкоядрени неутрофилни гранулоцити</li><li>Моноцити</li></ul><p><strong>При тежка бактериална инфекция може да се наблюдава:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span></li><ul><li>Токсични гранулации в цитоплазмеата на част от сегментоядрените неутрофили</li><li>Вакуолизация на цитоплазмата на част от сегментоядрените неутрофили</li><li>Олевяване</li></ul></ul><p><strong>Причините за неутрофилия са:</strong></p><ol><li>Тежко физическо натоварване, хипоксия, стрес или инжектиране на епинефрин.</li><li>Стомашно-чревни и чернодробни тумори, болест на Ходжкин, бъбречноклетъчен карцином и метастатично заболяване.</li><li>Реакции на свръхчувствителност и алергични реакции, ХМЛ, миелоидна метаплазия и polycythemia vera.</li><li>Радиация.</li><li>Остри инфекции (бактериални, някои вирусни, гъбични, паразитни).</li></ol><ul><li><span style=\"color: rgb(255, 0, 0)\">1, 2 и 5</span></li><li>1, 2 и 3</li><li>1, 3 и 4</li><li>3, 4 и 5</li></ul><p><strong>Кое твърдение за аномалията на Pelger-Huët е НЕВЯРНО:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Аномалията на Pelger-Huët е злокачествено заболяване на левкоцитите</span></li></ul><p><strong>Понятието „buffy coat“ включва:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Бели кръвни клетки и тромбоцити</span></li></ul><p><strong>Защо цитоплазмата на базофилния еритробласт е базофилна?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">поради голямото количество РНК;</span></li><li><span style=\"color: rgb(255, 0, 0)\">въпреки, че е започнал синтез на хемоглобин, преобладаващото количество РНК маскира цвета на малкото количество хемоглобин</span></li></ul><p><strong>На какво се дължи феноменът „олевяване“ в диференциалната кръвна картина?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Поява на млади форми на неутрофилните гранулоцити в периферната кръв</span></li></ul><p><strong>Кои от изброените отговарят на следната морфологична характеристика – нуклеарни клетки с тъмносиньо-виолето ядро с плътен хроматин, заемащо по-голямата част от клетката; делът им при деференциално броене е между 22 и 40 % при възрастни, но в ранна детска възраст представляват преобладаващ тип левкоцити:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лимфоцити</span></li></ul><p><strong>Кои са методите за получаване на костен мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Аспирация на костен мозък</span></li><li><span style=\"color: rgb(255, 0, 0)\">Биопсия на костен мозък</span></li></ul><p><strong>Какво e ‘’целуларитет на костен мозък’’?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">пространството, което заемат кръвните клетки в % спрямо общото пространство от клетки, включващи стромните елементи и мастите</span></li></ul><ul></ul><p><strong>Кое твърдение за изследването на костен мозък НЕ е вярно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Че целуларитетът се оценява на голямо увеличение</span> (<span style=\"color: rgb(0, 176, 80)\">обикновено се прави на малко увеличение</span>)</li></ul><p><strong>Пациент има анемия, овални макроцити и хиперсегментирани неутрофили. Кое от следните изследвания би било най-ефективно за диференциалната диагноза на това състояние?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Нива на витамин В12 и фолати</span></li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"transition: background-color 0.3s\">ЛЕВКЕМИИ</h1><p><strong>Прекият прекурсор на Миелоцита е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Промиелоцит</span></li><li>Метамиелоцит</li><li>Миелобласт</li><li>Неутрофил</li></ul><p><strong>Най-голяматa клетка от миелоидния ред е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">промиелоцит</span></li><li>миелоцит</li><li>метамиелоцит</li><li>миелобласт</li></ul><p><strong>Бластни клетки, които са миелопероксидаза-положителни и съдържат телца на Ауер, вероятно принадлежат към коя клетъчна линия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Миелоидна</span> </li><li>Лимфоидна</li><li>Мегакариоцитна</li><li>Еритроидна</li></ul><p><strong>От един проеритробласт се образуват:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">8-32 еритроцита</span></li><li>1-2 еритроцита</li><li>2-4 еритроцита</li><li>Всички изброени</li></ul><p><strong>Диференцирането на Миелобласта до Сегментоядрен гранулоцит, който преминава в циркулиращата кръв, протича приблизително за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">14 дни</span></li><li>10 дни</li><li>5 дни</li><li>7 дни</li></ul><p><strong>Процесът на съзряване на Миелобласта до зрял Гранулоцит се осъществява в по-голямата си част в:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Костен мозък</span></li><li>Слезка</li><li>Черен дроб</li><li>Тимус</li></ul><p><strong>Прекият прекурсор на Метамиелоцита е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Миелоцит</span></li><li>Промиелоцит</li><li>Миелобласт</li><li>Плурипотентната стволова клетка</li></ul><p><strong>В кръвта зрелите Неутрофилни гранулоцити имат полуживот:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">3-12 часа</span></li><li>2-3 дни</li><li>7 дни</li><li>10 дни</li></ul><p><strong>Най-голямата клетка от гранулоцитния ред е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Промиелоцит</span></li><li>Миелоцит</li><li>Миелобласт</li><li>Метамиелоцит</li></ul><p><strong>Тромбоцитите се образуват в цитоплазмата на ………….. и се отделят от нея чрез фрагментирането и.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегакариоцитите</span></li><li>Мегакариобластите</li><li>Промегакариоцитите</li><li>Всички изброени</li></ul><p><strong>Диференциацията от Плурипотентната кръвотворна стволова клетка до зрял Тромбоцит протича средно за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">10 дни</span></li><li>5 дни</li><li>5 часа</li><li>10 часа</li></ul><p><strong>Тромбоцитите живеят средно от 8 до 12 дни, като около 67-70% от тях са в циркулиращата кръв, а 30-33% се намират като резерв в:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Слезка</span></li><li>Черен дроб</li><li>Кости</li><li>Тимус</li></ul><p><strong>Най-голямата кръвна клетка в костния мозък е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегакариоцит</span></li><li>Еритробласт</li><li>Промиелоцит</li><li>Миелобласт</li></ul><p><strong>Материал от костен мозък се получава с помощта на различни методи в зависимост от целите на изследването, заболяването, възрастта на пациента и други фактори. Обикновено се използват два метода. Моля отбележете:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Стернална - аспирация</span></li><li><span style=\"color: rgb(255, 0, 0)\">Трепано - Биопсия</span></li></ul><p><strong>Предпочитани места за вземане на костен мозък при възрастни пациенти са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Sternum</li><li>Crista iliaca anterior</li><li>Crista iliaca posterior superior</li></ul></ul><p><strong>При деца до 1 год. възраст материал от костен мозък може да се вземе от:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тибиа</span></li><li>Стернална кост</li><li>Черепни кости</li><li>Бедрена кост</li></ul><p><strong>По отношение на целуларитета Костният мозък се оценява като:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">А+Б+В </span></li><ul><li>Нормоцелуларен</li><li>Хипоцелуларен</li><li>Хиперцелуларен</li></ul></ul><p><strong>У новородени и деца до 2год. възраст нормалният целуларитет на Костния мозък е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">75-100%</span></li><li>20-30%</li><li>40-50%</li><li>50-60%</li></ul><p><strong>В костния мозък на здрави възрастни пациенти отношението Миелоиден/Еритроиден ред е от порядъка на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">3:1 - 4:1</span></li><li>9:1 – 10:1</li><li>1:5</li><li>1:10</li></ul><p><strong>В костния мозък на пациенти с Мегалобластна анемия отношението Миелоиден/Еритроиден ред е от порядъка на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1:1</span></li><li>3:1 - 4:1</li><li>9:1 – 10:1</li><li>1:10</li></ul><p><strong>В костния мозък на пациенти с Левкемия отношението Миелоиден/Еритроиден ред:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Нараства до 10:1, дори 50:1</span></li><li>Намалява до 1:1</li><li>Нараства до 6:1</li><li>Не се променя</li></ul><p><strong>В костния мозък на здрави пациенти % на ядроносните червени кръвни клетки е от порядъка на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">15-35 %</span></li><li>10-20 %</li><li>50-60%</li><li>5-10%</li></ul><p><strong>Намалена активност на Алкалната фосфатаза в левкоцитите се наблюдава при пациенти с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХМЛ&nbsp;</span><p>(<span style=\"color: rgb(0, 176, 80)\">функционално дефектни са гранулоцитите, които синтезират LA</span><span style=\"color: rgb(0, 176, 80)\">P</span>)</p></li><li>Полицитемия вера</li><li>Левкемоидна реакция (<span style=\"color: rgb(0, 176, 80)\">тука има баш ще има завишен LAP, защото бая гранулоцити</span>)</li><li>ХЛЛ&nbsp;</li></ul><p><strong>Алкалната фосфатаза в левкоцитите е с нормална или повишена активност при пациенти с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Левкемоидна реакция от гранулоцитен тип</span></li><li>ХМЛ&nbsp;</li><li>ХЛЛ&nbsp;</li><li>Пароксизмална нощна хемоглобинурия</li></ul><p><strong>Най-характерната клетка на периферна кръвна натривка при пациент с ОЛЛ e:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лимфобласт</span></li><li>Миелобласт</li><li>Миелоцит</li><li>Лимфоцит</li></ul><p><strong>Кое твърдение остносно инфекциозната монокуклеоза е вярно:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span></li><ul><li>Причинява се от Epstain-Barr вирус</li><li>Протича с катарална ангина и лимфаденопатия</li><li>Характерна находка е лимфоцитоза, с наличие на реактивни лимфоцити</li></ul></ul><p><strong>Левкемия, която включва червените кръвни клетки и гранулоцитните прекурсори се означава като:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Еритролевкемия</span></li><li>Миелобластна левкемия</li><li>Лимфобластна левкемия</li><li>Монобластна левкемия</li></ul><p><strong>Над 95% от пациентите с ……….. имат Филаделфийска хромозома (Ph). </strong><span style=\"color: rgb(0, 176, 80)\">t(9;22)</span></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХМЛ</span></li><li>ХЛЛ</li><li>Остра миелобластна левкемия</li><li>Остра лимфобластна левкемия</li></ul><p><strong>При коя Левкемия обикновено няма тромбоцитопения</strong><strong>?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХМЛ</span>&nbsp;<p>(<span style=\"color: rgb(0, 176, 80)\">често дори има тромбоцитоза</span>)</p></li><li>Остра лимфобластна левкемия</li><li>ХЛЛ&nbsp;</li><li>Остра миелобластна левкемия</li></ul><p><strong>Левкемията, при която често има полицитемия в ранните стадии на заболяването е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХМЛ</span></li><li>Остра лимфобластна левкемия</li><li>Остра миелобластна левкемия</li><li>ХЛЛ</li></ul><p><strong>Множественият миелом никога няма да се прояви с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишаване на IgG, IgA, IgM, IgD</span></li><li>Миеломни клетки</li><li>Понижаване на IgG, IgA, IgM, IgD</li><li>Клетки на Mott</li></ul><p><strong>Какво показва транслокацията t(15; 17)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра промиелоцитна левкемия, добра прогноза </span>(<span style=\"color: rgb(0, 176, 80)\">М3 подтип, добра прогноза щото има таргетна терапия)</span></li><li>ХМЛ</li><li>ОЛЛ с лоша прогноза</li><li>ОМЛ с лоша прогноза</li></ul><p><strong>Каква е прогнозата при ОЛЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Добра прогноза при деца, но не толкова добра при възрастни пациенти</span></li><li>Добра прогноза при възрастни пациенти, но не толкова добра при деца</li><li>Добра прогноза, ако се лекува рано</li><li>Добра прогноза, ако не се лекува</li></ul><p><strong>С какво се асоциира делеция р53?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХЛЛ - лоша прогноза </span>(<span style=\"color: rgb(0, 176, 80)\">TP53 в табличка го има като лоша прогноза</span>)</li><li>ХЛЛ - добра прогноза</li><li>ОМЛ - добра прогноза</li><li>Миелодиспластичен синдром</li></ul><p><strong>Отбележете имунната дисфункция, при която може да има положителен тест на Coombs или хипогамаглобулинемия:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХЛЛ </span>(<span style=\"color: rgb(0, 176, 80)\">Coombs - автоантитела, хипогламаглобулинемия, щото лимфоцитите са дефектни</span>)</li><li>Вирусна инфекция</li><li>B-клетъчна ОЛЛ&nbsp;</li><li>Мултиплен миелом</li></ul><p><strong>Посочете заболяване, при което може да има хипоспления или функционална аспления:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХЛЛ </span>(<span style=\"color: rgb(0, 176, 80)\">никва идея защо, ама няма да са другите</span>)</li><li>Полицитемия вера (<span style=\"color: rgb(0, 176, 80)\">chatgpt вика това, ае бахти въпроса е)</span></li><li>ХМЛ</li><li>Косматоклетъчна левкемия</li></ul><p><strong>Кой е най-значимият тип клетки, увеличен при Първична миелофиброза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мегакариоцити</span></li><li>Тромбоцити</li><li>Моноцити</li><li>Лимфоцити</li></ul><p><strong>Кой е най-значимият тип клетки, увеличен при ХМЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Гранулоцити</span></li><li>Мегакариоцити</li><li>Лимфоцити</li><li>Еритробласти</li></ul><p><strong>При ХЛЛ е налице:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Абсолютна лимфоцитоза</li><li>Лимфоцити, морфологично неотличими от нормалните</li><li>Характерна находка на микроскопски препарат са т.нар. гумпрехтови сенки</li></ul></ul><p><strong>Съгласно FAB /French-American-British Cooperative Group/ класификацията, която се основава на морфологичната характеристика на клетките, оценена със светлинна микроскопия и на цитохимични реакции, острите лимфобластни левкемии се подразделят на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Три групи: L1 - L3</span></li><li>Пет групи: L1 – L5</li><li>Седем групи: L1 – L7</li><li>Две групи: L1, L2</li></ul><p><strong>Съгласно FAB /French-American-British Cooperative Group/ класификацията, която се основава на морфологичната характеристика на клетките, оценена със светлинна микроскопия и на цитохимични реакции, острите миелоблстни левкемии се подразделят на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Осем групи: М0 – М7</span></li><li>Три групи: М1 - М3</li><li>Пет групи: М1 – М5</li><li>Десет групи: М0 – М9</li></ul><p><strong>Какво означава понятието Нiatus leukaemicus?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">На натривка от периферна кръв на пациент с ХМЛ се наблюдават левкемични, атипични бласти и зрели гранулоцити, като липсват междинните матурационни форми</span></li><li>На натривка от периферна кръв на пациент с ХМЛ се наблюдават всички клетки от Миелоцит до зрял Гранулоцит</li><li>На натривка от периферна кръв на пациент с ХМЛ се наблюдават само Миелобласти</li><li>На натривка от периферна кръв на пациент с ХМЛ се наблюдават Миелобласти и Промиелоцити</li></ul><p><strong>Симптоми: Постепенно начало със спленомегалия, левкоцитоза с олевяване и &lt;5% бласти са типични за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ХМЛ</span></li><li>ОЛЛ</li><li>ОМЛ</li><li>ХЛЛ</li></ul><p><strong>B-клетъчно злокачествено заболяване, характеризиращо се с абнормална пролиферация на плазматични клетки, способни да произвеждат моноклонален имуноглобулин (M протеин) се нарича:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Мултиплен миелом</span></li><li>ХМЛ</li><li>ХЛЛ</li><li>Миелофиброза</li></ul><p><strong>Нормално плазматичните клетки в КМ са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&lt;5%</span></li><li>10%</li><li>20%</li><li>Не се откриват</li></ul><p><strong>На натривка от периферна кръв на пациенти с Мултиплен миелом се наблюдават:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Нормоцитни, нормохромни еритроцити</li><li>Монетни стълбове от еритроцити</li><li>Плазмоцитоидни лимфоцити</li></ul></ul><p><strong>На натривка от Костен мозък на пациенти с Мултиплен миелом се наблюдават:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Увеличен брой плазматични клетки &gt; 10%</li><li>Повишена честота на митозите и на дву- и три-ядрените плазматични клетки</li><li>В цитоплазмата на клетките може да се съдържат вакуоли, хиалинни капки, телца на Russell</li></ul></ul><p><strong>При пациенти с Мултиплен миелом има склонност към кървене поради:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Анти-von Willebrand factor</li><li>Тромбоцитопения</li><li>Нарушена функция на тромбоцитите</li></ul></ul><p><strong>При пациенти с Мултиплен миелом:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени са верни</span></li><ul><li>Приблизително 30% произвеждат леки вериги в урината и тежки вериги в кръвта</li><li>При около 10% от пациентите миеломните клетки произвеждат само леки вериги, миеломът се нарича тип „Bence-Jones”</li><li>При 1-2% от пациентите миеломните клетки произвеждат малко или не произвеждат моноклонален протеин, болестта се нарича „Несекретиращ миелом”</li></ul></ul><p><strong>При пациенти с Мултиплен миелом на серумна електрофореза се демонстрира:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Моноклонална гамапатия (парапротеин, M-градиент)</span></li><li>Пик в областта на α -глобулините</li><li>Пик в областта на β-глобулините</li><li>Всички изброени</li></ul><p><strong>Особени форми на Мултиплен миелом са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Плазмоцитна левкемия</li><li>Тлеещ множествен миелом</li><li>Солитарен плазмоцитом</li></ul></ul><p><strong>В зависимост от клиничния ход на протичане, левкемиите се разделят на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остри и хронични</span></li></ul><p><strong>Острите левкемии се срещат във всички възрастови групи като:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ОЛЛ е по-честа при деца</span></li><li>ОМЛ е по-честа при деца</li><li>ОЛЛ е по-честа при възрастни</li><li>ОМЛ не се среща при възрастни</li></ul><p><strong>Посочете кое от следните заболявания е показание за изследване на костен мозък:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></li><ul><li>Съмнение за левкемия</li><li>Метастази при нехематологични злокачествени заболявания</li><li>Невробластом</li></ul></ul><p><strong>Кой тип левкемия се характеризира с молекулярно-генетичната аномалия BCR-ABL 1?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хронична миелогенна левкемия</span></li><li>Остра миеломоноцитна левкемия</li><li>Остра еритролевкемия</li><li>Остра мегакариоцитна левкемия</li></ul><p><strong>С какво се характеризират острите левкемии?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пролиферация на незрели злокачествени клетки</span></li><li>Пролиферация на по-зрели клетки</li><li>По-бавен клиничен ход</li><li>Граница от 150% за определяне</li></ul><p><strong>С какво се характеризират хроничните левкемии?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Пролиферация на по-зрели клетки</span></li><li>Пролиферация на незрели злокачествени клетки</li><li>По-бърз клиничен ход</li><li>Граница от 150% за определяне</li></ul><p><strong>Каква е кръвната картина на множествения миелом? (ПОСОЧЕТЕ ГРЕШНОТО):</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Нормално СУЕ</span> (<span style=\"color: rgb(0, 176, 80)\">При миелом СУЕ винаги е силно ускорено</span>)</li><li>Умерено изразена анемия</li><li>Lks, Thr – често в референтни граници</li><li>СУЕ и вискозитетът на плазмата са силно увеличен</li></ul><p><strong>Кое твърдение за острите (прекурсорни) левкемии е грешно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Наблюдават се хиперпролиферативен костен мозък с всички стадии на матурация и деференциация на клетките</span></li><li>Развиват се в резултат от генетични мутации, водещи до увеличена пролиферация и преживяемост</li><li>Резултат са на клонална експанзия на единична родоначална клетка</li><li>В костния мозък се наблюдават натрупване на бласти</li></ul><p><strong>Коя е най-честата левкемия при деца?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра лимфобластна левкемия</span></li><li>Остра миелоидна левкемия</li><li>Хронична миелогенна левкемия</li><li>Хронична лимфоцитна левкемия</li></ul><p><strong>Кое НЕ е диагностичен критерий за ХЛЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лимфобласти над 20% от ядрените клетки в периферна кръв</span> (<span style=\"color: rgb(0, 176, 80)\">това е за острите</span>)</li><li>Персистиране на клонални В-лимфоцити&nbsp;<p>5х10<sup>9</sup>/L</p> в периферна кръв за период от 3 месеца</li><li>Морфология: малки зрели, но функционално непълноценни лимфоцити в периферна кръв</li><li>Наличие на Гумпрехтови сенки в периферна кръв</li></ul><p><strong>Кои от изброените симптоми НЕ са характерни за мононуклеозата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">болки в ставите</span></li><li>висока температура</li><li>подути лимфни възли</li><li>зачервено гърло</li></ul><p><strong>При ХЛЛ се наблюдава:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">всички изброени</span></li><ul><li>абсолютна лимфоцитоза</li><li>лимфоцити, морфологично неотличими от нормалните</li><li>характерна морфологична находка са т.нар. гумпрехтови сенки</li></ul></ul><p><strong>Момче на 12г. е с температура, отпадналост, ангина, трудно прeглъщане. Обективно е установено: увеличени лимфни възли субмандибуларно, черен дроб на ребрена дъга, слезка – умерено увеличена. Лабораторни данни: Hgb –130 g/L, WBC – 21x10<sup>9</sup>/L, PLT - 250x10<sup>9</sup>/L, СУЕ – 40mm/h. ДКК: St – 5%, Sg – 25%, Ео – 3%, Мо – 10%, Ly – 57%. Микроскопски от кръвната картина се установяват реактивни лимфоцити над 30%. Най-вероятната диагноза е</strong>:<strong></strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">инфекциозна мононуклеоза</span></li><li>ОЛЛ</li><li>ОМЛ</li><li>инфекциозна лимфоцитоза</li></ul><p><strong>L1 - малки, униформни лимфобласти; L2 - големи, плеоморфни лимфобласти; L3 - тип Бъркит, е класификация (FAB) на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра лимфобластна левкемия</span></li><li>Хронична лимфоцитна левкемия</li><li>Остра миелоидна левкемия</li><li>Хронична миелоидна левкемия</li></ul><p><strong>Според класификацията на СЗО, с изключение на левкемиите със специфични генетични аномалии, минималният процент бласти, необходим за диагноза остра левкемия, е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">20%</span></li><li>10%</li><li>30%</li><li>50%</li></ul><p><strong>Бластни клетки, които са миелопероксидаза-положителни и съдържат телца на Ауер, вероятно принадлежат към коя клетъчна линия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Миелоидна</span></li><li>Лимфоидна</li><li>Мегакариоцитна</li><li>Еритроидна</li></ul><p><strong>Бластите при M4 левкемия вероятно ще покажат какви резултати от оцветяването?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">MPO+, PAS-, NSE+</span></li><li>MPO+, PAS-, NSE-</li><li>MPO-, PAS+, NSE-</li><li>MPO-, PAS+, NSE+</li></ul><p><strong>Променлив брой бели кръвни клетки, над 20% бласти, телца на Ауер, анемия и тромбоцитопения са характеристики на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра миелоидна левкемия</span></li><li>Хронична миелоидна левкемия</li><li>Остра лимфна левкемия</li><li>Хронична лимфоцитна левкемия</li></ul><p><strong>Кое от следните НЕ СЕ свързва с лоша клинична прогноза при остра лимфоидна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хипердиплоидия</span></li><li>Висок брой бели кръвни клетки при диагностициране</li><li>Филаделфийска хромозома (<span style=\"color: rgb(0, 176, 80)\">добра прогноза за ХМЛ!</span>)</li><li>Диагностициране при кърмачета под 1-годишна възраст</li></ul><p><strong>Специално оцветяване за диференциална диагноза между хронична миелоидна левкемия и левкемоидна реакция е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">LAP (Левкоцитна алкална фосфатаза)</span></li><li>PAS (Периодна киселина - Шиф)</li><li>MPO (Миелопероксидаза)</li></ul><p><strong>64-годишна жена е планирана за планова операция на херния. Тя съобщава за нарастваща умора през последната година, която отдава на стрес в работата. При физикален преглед няма лимфаденопатия и хепатоспленомегалия. Като част от предоперативните изследвания, ПКК показва: общ брой WBC 26,000/μl, Hgb 11.2 g/dL, Hct 33.3%, MCV 90 fL и брой тромбоцити 163,000/μl. Периферната кръвна натривка показва множество малки, зрели лимфоцити. Кое от следните състояния е най-вероятно да има тя:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хронична лимфоцитна левкемия&nbsp; </span>(<span style=\"color: rgb(0, 176, 80)\">възрастна <p>→</p> хронично; умора → анемия; има левкоцитоза; малки, зрели лимофцити&nbsp;</span><p><span style=\"color: rgb(0, 176, 80)\">→ патогномично за ХЛЛ</span>)</p></li><li>Цитомегаловирусна инфекция</li><li>Левкемоидна реакция</li><li>Инфекциозна мононуклеоза </li><li>Остра лимфна левкемия</li></ul><p><strong>CD13, CD33 и CD117 са общи повърхностни клетъчни маркери, които се установяват като положителни при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра миелоидна левкемия</span></li><li>Остра лимфна левкемия</li><li>Хронична лимфоцитна левкемия </li><li>Хронична миелоидна левкемия</li></ul><p><strong>45-годишен мъж е с треска и кашлица от един месец. Рентгенографията на гръдния кош разкрива ретикулонодуларен модел с кавитарни лезии (каверни) в горния лоб. Храчката му е положителна за киселинно-устойчиви бацили. ПКК показва: Hgb 14.2 g/dL, MCV 92, брой тромбоцити 225,000 и брой WBC 44,500 с 59% сегментоядрени, 20% пръчкоядрени, 8% метамиелоцити, 4% миелоцити, 2% промиелоцити, 5% лимфоцити и 2% моноцити – екстремно олевяване. Биопсията на костен мозък показва миелоидна хиперплазия с под 5% бласти. Коя от следните лабораторни находки вероятно е налице?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишена левкоцитна алкална фосфатаза&nbsp;</span><p>(<span style=\"color: rgb(0, 176, 80)\">човекът има туберкулоза -&gt; лимфоидна реакция</span>)</p></li><li>Кариотип с t(9;22) </li><li>Моноклонална гамопатия</li><li>Повишен D-димер</li><li>Положителен TdT</li></ul><p><strong>71-годишен мъж се представя с повишен брой бели кръвни клетки, висок процент бласти (35%) в периферната кръв и анемия. Коя е най-вероятната диагноза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра миелоидна левкемия </span>(<span style=\"color: rgb(0, 176, 80)\">може и ОЛЛ, но ОМЛ е много по-честа пр ивъзрастни</span>)</li><li>Остра Т-лимфобластна левкемия </li><li>Хронична миелоидна левкемия</li><li>Остра Т-лимфобластна левкемия</li></ul><p><strong>Кое от следните е вярно за хроничната миелоидна левкемия:</strong></p><ol><li>Нормоцитна анемия е налице при по-голямата част от пациентите при диагностициране и обикновено могат да се открият единични нормобласти.</li><li>Тромбоцитоза е налице при повече от половината, а по-малко от 15% имат тромбоцитопения.</li><li>Костният мозък е подчертано хиперцелуларен, главно в резултат на гранулоцитна пролиферация, като са представени всички стадии.</li><li>Неутрофилната алкална фосфатаза е силно намалена или липсва при повече от 90% от пациентите с ХМЛ.</li><li>Неутрофилната алкална фосфатаза е силно повишена при повече от 90% от пациентите с ХМЛ.</li></ol><ul><li><span style=\"color: rgb(255, 0, 0)\">1, 2, 3 и 4</span></li><li>1 и 2</li><li>1, 2 и 3</li><li>1, 2, 3 и 5</li></ul><p><strong>Какво представляват левкемиите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Малигнени неоплазии на костен мозък, дължащи се на обща геномна нестабилност – хромозомни транслокации, делеции, инверсии, инсерции; инактивиране на тумор-супресорни гени; активиране на онкогени.</span></li></ul><p><strong>На какво се базира FAP-класификацията на левкемиите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Морфологични белези и цитохимични оцветявания</span></li></ul><p><strong>Каква е клиниката на ОМЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Анеми;</span></li><li><span style=\"color: rgb(255, 0, 0)\">WBC признаки на функционална недостатъчност;</span></li><li><span style=\"color: rgb(255, 0, 0)\">Тромбоцитопения;</span></li><li><span style=\"color: rgb(255, 0, 0)\">Костни болки</span></li></ul><p><strong>Какво представляват Гумпрехтовите сенки наблюдават при ХЛЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">разрушени лимфоцити поради повишената им ранимост;</span></li><li><span style=\"color: rgb(255, 0, 0)\">наблюдават се на натривки от периферна кръв</span></li></ul><p><strong>Критерии за диагноза „остра миелоидна левкемия“ (според СЗО):</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Миелобласти &gt;20% от ядрените клетки в костен мозък (при изброяване на 500 клетки) или при налични хромозомни аномалии диагнозата е независима от броя на бластите: t(8,21)(q22;q22); inv(16)(p13q22); t(16;16)(p13,q22); t(15,17)(q22;q12)</span></li></ul><p><strong>Кои са стадиите в протичането на хроничната миелогенна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">хронична фаза – бласти и промиелоцити в КМ: &lt;5% (3-4 години)</span></li><li><span style=\"color: rgb(255, 0, 0)\">фаза на обостряне – бласти и промиелоцити в КМ: 5%÷20% (1-2 години)</span></li><li><span style=\"color: rgb(255, 0, 0)\">фаза на бластна трансформация – бласти и промиелоцити в КМ &gt;20%. (3-6 месеца)</span></li></ul><p><strong>В какво се изразява бимодалното разпределение на появата на ОЛЛ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">пик на поява на 2-5 год. възраст и втори пик след 50 год. възраст</span></li></ul><p><strong>Необходимо ли е за поставяне на диагноза ХЛЛ костномозъчна биопсия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Не</span></li></ul><p><strong>Лабораторни резултати: Хб-102, WBC-70X10<sup>9</sup>, Ery-3.5x10<sup>12</sup>, Thr 36x10<sup>9</sup>. Преобладават миелобласти с пръчици на Auer, пероксидазна активност (+). Каква е най-вероятната диагноза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остра миелобластна левкемия</span></li></ul><p><strong>Кой ензим се използва като маркер за разграничаване на ХМЛ от левкемоидна реакция:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Алкална фосфатаза в левкоц</span><span style=\"color: rgb(255, 0, 0)\">итите</span>&nbsp;(<span style=\"color: rgb(0, 176, 80)\">ниска при ХМЛ, висока при левкемоидна реакция</span>)</li></ul><p><strong>Кое е най-важното лабораторно изследване при съмнение за мултиплен миелом?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Изследване на серум и урина за моноклонална гамопатия</span><span style=\"color: rgb(255, 0, 0)\"> (M-протеин)</span></li></ul><p><strong>При гранулоцитната левкемоидна реакция обикновено се наблюдава ВСИЧКО ОСВЕН:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Изразена еозинофилия и базофилия</span> (<span style=\"color: rgb(0, 176, 80)\">те са характерни за ХМЛ, не за левкемоидна реакция</span>)</li></ul><p><strong>При коя левкемия обикновено ИМА тромбоцитопения?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ОЛЛ, ХЛЛ, OMЛ</span></li></ul><p><strong>Кое твърдение е вярно за периферната кръвна картина при Хронична миелогенна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Превалират зрели клетки в периферията</span></li></ul><p><strong>Кое от посочените НЕ е характерно за левкемиите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Микроцитна анемия</span></li></ul><p><strong>При кои видове левкемия се наблюдава феноменът \"Hiatus leukaemicus\"?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Остри левкемии</span></li></ul><p><strong>Как се променят стойностите на левкоцитите и тромбоцитите при Остра миелоидна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тромбоцитопения, левкоцитоза</span></li></ul><p><strong>Кое твърдение е вярно по отношение на честотата на левкемиите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Острата лимфобластна левкемия (ОЛЛ) е най-честата при деца</span></li></ul><p><strong>Кои състояния са индикация за провеждане на изследване на костен мозък?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички посочени </span>(левкемии, анемии с неизяснен произход и др.)</li></ul><p><strong>Кое твърдение за изследването на костен мозък НЕ е вярно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Че целуларитетът се оценява на голямо увеличение</span> (<span style=\"color: rgb(0, 176, 80)\">обикновено се прави на малко увеличение</span>)</li></ul><p><strong>С кое заболяване се прави диференциална диагноза при наличие на левкемоидна гранулоцитна реакция?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хронична миелогенна левкемия</span></li></ul><p><strong>Кои лабораторни находки са характерни за Хроничната миелогенна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Понижена алкална фосфатаза в левкоцитите, повишени еозинофили и базофили</span></li></ul><p><strong>Какво е клиничното значение на мутациите в протеина p53 при Остра миелоидна левкемия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Свързват се с лоша прогноза</span></li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"transition: background-color 0.3s\">ХЕМОСТАЗА</h1><p><strong>С помощта на кой тест се откриват аномалии във фибриногена?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тромбиново време</span></li><li>Протромбиново време</li><li>Време на кървене</li><li>Д-димери</li></ul><p><strong>Дефицитът на кой витамин ще предизвика удължаване в коагулацията?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">вит К</span></li><li>вит А </li><li>вит Д</li><li>вит В<sub>12</sub></li></ul><p><strong>Функционален дефицит на коагулационен фактор VIII-C води до?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемофилия А</span></li><li>Хемофилия Б</li><li>Придобит имунен дефицит</li><li>Тромбофилия</li></ul><p><strong>Функционален дефицит на коагулационен фактор IX води до?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемофилия Б</span></li><li>Хемофилия А</li><li>Придобит имунен дефицит</li><li>Тромбофилия</li></ul><p><strong>Как се нарича процесът, при който тромбоцитите и плазмените фактори на кръвосъсирването реагират, за да преобразуват фибриногена във фибрин?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Коагулация</span></li><li>Хемолиза</li><li>Вазоконстрикция</li><li>Хемофилия</li></ul><p><strong>В кой орган се синтезират плазмените фактори на кръвосъсирването?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Черен дроб</span></li><li>Слезка</li><li>Тимус</li><li>Панкреас</li></ul><p><strong>Кой минерал е от съществено значение за коагулацията?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Калций</span></li><li>Калий </li><li>Магнезий </li><li>Йод</li></ul><p><strong>Кой от изброените по-долу тестове се използва за мониториране на пациенти, приемащи перорални антикоагуланти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Протромбиново време</span></li><li>Фибриноген</li><li>APTT</li><li>Д-димери</li></ul><p><strong>Кой от изброените по-долу тестове се използва за мониториране на пациенти на хепаринова терапия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">АПТТ</span></li><li>Фибриноген</li><li>Д-димери&nbsp;</li><li>Протромбиново време</li></ul><p><strong>Какъв е биологичният материал, който се използва за определяне на параметрите на хемостазата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Бедна на тромбоцити цитратна плазма</span></li><li>Серум</li><li>ЕДТА-плазма</li><li>Пълна кръв</li></ul><p><strong>Единственият антикоагулант, който се използва в лабораторните методи за изследване на параметрите на хемостазата е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тринатриев цитрат</span></li><li>ЕДТА-плазма</li><li>Литиев хепаринат</li><li>Натриев флуорид</li></ul><p><strong>За да се получи надежден лабораторен резултат при изследване на параметрите на хемостазата е от изключително значение да се спази точното съотношението кръв/антикоагулант, което е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">9:1 </span></li><li>1:9</li><li>5:1 </li><li>1:5</li></ul><p><strong>Хепаринът не е подходящ антикоагулант за изследване на хемостаза, защото…</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Инхибира тромбина</li><li>Инхибира ф XIIa, фXIa</li><li>Инхибира ф Xa, фIXa</li></ul></ul><p><strong>Проникването на иглата през тъканите и съдовата стена освобождава ….., който попаднал в кръвната проба, активира тромбоцитите и коагулацията и ……. лабораторно измерваното време на кръвосъсирване.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тъканен фактор; скъсява</span></li><li>Тъканен фактор; удължава</li><li>Фибриноген; скъсява</li><li>Фибриноген; удължава</li></ul><p><strong>Когато се взема серия от вакуумни епруветки за различни лабораторни анализи, епруветката за изследване на хемостаза не трябва да бъде след епруветки съдържащи:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Хепарин</li><li>К<sub>2</sub>ЕДТА</li><li>Натриев флуорид</li></ul></ul><p><strong>Пресяващи методи за изследване на хемостазата са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Протромбиново време</li><li>Активирано парциално тромбопластиново време</li><li>Тромбиново време</li></ul></ul><p><strong>Клинични показания за измерване на Протромбиново време (РТ) са:</strong></p><ol><li>Лабораторен контрол на перорално антикоагулантно лечение с антагонисти на вит К</li><li>Недоимък на вит К</li><li>Оценка на функционалното състояние на черния дроб</li><li>Предоперативно</li></ol><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><li>1, 4 </li><li>1, 2 </li><li>2, 3, 4</li></ul><p><strong>Резултатите за Протромбиново време (РТ) се изразяват посредством:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Секунди</li><li>Процент активност, изчислен от калибрационна крива</li><li>INR (Международно нормализирано отношение)</li></ul></ul><p><strong>Удължено Протромбиново време (РТ) предполага дефицит на факторите от:</strong></p><ul><li>Външната с-ма</li><li>Вътрешната с-ма </li><li>Общия път </li><li><span style=\"color: rgb(255, 0, 0)\">А, В</span></li><li>Б, В </li><li>А, Б, В</li></ul><p><strong>Дефицит на кои от следните фактори на кръвосъсирването предполага удълженото Протромбиново време (РТ)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ф I, фII, фV, фVII, фX</span></li><li>ф I, фII, фVII</li><li>фI, фII, фIII, фVII, фIX</li><li>фI, фII, фIII, фVII, фIX, фXII</li></ul><p><strong>Недоимъкът на вит К и Кумариновите препарати имат еднакъв механизъм на действие -чрез намаляване на функциите на ф-рите II, VII, IX, X, което води до:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Удължаване на РТ</span></li><li>Скъсяване на РТ</li><li>Скъсяване на АРТТ</li><li>Удължаване на АРТТ</li></ul><p><strong>Активираното парциално тромбоплстиново време (АРТТ) е коагулационен пресяващ тест за оценка функцията на факторите от:</strong></p><ul><li>Външната с-ма</li><li><p>Вътрешната с-ма</p><br></li><li>Общия път </li><li>А, В </li><li><span style=\"color: rgb(255, 0, 0)\"><p>Б, В</p><br></span></li><li>А, Б, В</li></ul><strong>Чрез Активираното парциално тромбопластиново време (АРТТ) се откриват вродени и придобити дефицити на всички прокоагулантни фактори с изключение на:</strong><br><ul><li><span style=\"color: rgb(255, 0, 0)\">фVII, фXIII</span></li><li>фII, фVII</li><li>фII, фIII, фXIII</li><li>фVII</li></ul><p><strong>Тестът АРТТ е по-чувствителен към дефекти на факторите от вътрешната система и е по-малко чувствителен към факторите на общия път. Към последните се отнасят:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фибриноген, фII, фV, фX</span></li><li>Фибриноген, фIII, фVII, фX</li><li>Фибриноген, фII, фVIII, фX</li><li>Фибриноген, фIII, фVII, фIX</li></ul><p><strong>Как се изразяват резултатите за АРТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Секунди</span></li><li>Процент активност, изчислен от калибрационна крива</li><li>INR (Международно нормализирано отношение)</li><li>Всички изброени</li></ul><p><strong>АРТТ &gt; 2,5 пъти над горната референтна граница при пациенти, които се лекуват с нефракциониран хепарин е показател за риск от:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Кръвоизливи</span></li><li>Тромбофилия</li><li>Тромбози</li><li>Всички изброени</li></ul><p><strong>Към аномалия в коя система насочва удълженото АРТТ, при РТ в референтни граници?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вътрешна система</span></li><li>Външна система</li><li>Общ път</li><li>Всички изброени</li></ul><p><strong>Едновременното удължаването на АРТТ и РТ предполага дефект в …</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Общ път</span></li><li>Вътрешна система</li><li>Външна система</li><li>Всички изброени</li></ul><p><strong>Кои са причините за изолирано удължаване на АРТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Лупусни антикоагуланти</li><li>Дефицит на фVIII и/или vWF</li><li>Дефицит на фIX</li></ul></ul><p><strong>Когато се получи удължено ….., за което няма обяснение, първата стъпка е да се изясни дали няма контаминация с хепарин.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Активирано парциално тромбопластиново време (АРТТ)</span></li><li>Протромбиново време (РТ)</li><li>Тромбиново време (ТТ)</li><li>Рептилазно време</li></ul><p><strong>Как се променя АРТТ при увеличена активност на фVIII ( острофазни реакции )?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Скъсява се</span></li><li>Удължава се</li><li>Не се променя</li></ul><p><strong>Тромбиновото време (ТТ) може да бъде удължено в резултат на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Аномалии на фибриногена (вродени или придобити)</li><li>Наличие на антитромбини</li><li>Уремия</li></ul></ul><p><strong>Към клиничните показания за измерване на Фибриноген се отнасят:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Откриване на вродени/придобити количествени дефицити или структурни дефекти на фибриногена</li><li>ДИК синдром</li><li>Остри/хронични възпалителни заболявания</li><li>Неизяснени причини за кървене</li></ul></ul><p><strong>Резултатите за Фибриноген се изразяват в:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">g/l</span></li><li>Процент</li><li>Секунди</li><li>Всички изброени</li></ul><p><strong>Референтните граници за Фибриноген в кръвта на здрави пациенти са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1,5 - 4 g/l</span></li><li>20 - 40 sec</li><li>100 – 150 %</li><li>Всички изброени</li></ul><p><strong>При нива на Фибриноген под критичните, ….., съществува опасност от ……</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&lt; 0.8 g/l; кръвоизливи</span></li><li>&lt; 0.8 g/l; тромбози</li><li>&lt; 1,5 g/l; тромбози</li><li>&gt; 5.0 g/l; кръвоизливи</li></ul><p><strong>Към клиничните показания за измерване активността на фVIII се отнасят:</strong></p><ul><li>Хемофилия А и болест на von Willebrand</li><li>Хемофилия В и болест на von Willebrand</li><li>Проследяване ефекта от лечението на Хемофилия А</li><li>Проследяване ефекта от лечението на Хемофилия В</li><li><span style=\"color: rgb(255, 0, 0)\"><p>А, В</p><br></span></li><li><p>Б, Г</p></li></ul><p><strong>При Хемофилия А се установява:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Удължаване на АРТТ</li><li>Намалена активност на фVIII</li><li>РТ, брой тромбоцити и време на кървене в реф. граници за здрави (<span style=\"color: rgb(0, 176, 80)\">време на кървене в норма, защото той показва първична хемостаза, която не е засегната от хемофилията</span>)</li></ul></ul><p><strong>Лица с активност на фVIII ……….. нямат симптоми на Хемофилия А.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&gt; 30%</span></li><li>&gt; 5%</li><li>&gt; 10%</li><li>&gt; 1%</li></ul><p><strong>Тежестта на Хемофилия А зависи от нивото на активност на фVIII в плазмата и при стойности …….. предизвиква тежка хемофилия със спонтанни кръвоизливи; наблюдавана се при 50-60% от пациентите.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&lt; 1%</span></li><li>&lt; 5%</li><li>&lt; 10%</li><li>&lt; 30%</li></ul><p><strong>Към клиничните показания за измерване активността на фIX се отнасят:</strong></p><ul><li>Хемофилия B</li><li>Хемофилия A и болест на von Willebrand</li><li>Проследяване ефекта от лечението на Хемофилия A</li><li>Проследяване ефекта от лечението на Хемофилия В</li><li><span style=\"color: rgb(255, 0, 0)\">А, Г</span></li><li>Б, В</li></ul><p><strong>Към лабораторните данни при Хемофилия В се отнасят:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Удължаване на АРТТ</li><li>Намалена активност на фIX</li><li>РТ и брой тромбоцити в реф. граници за здрави</li></ul></ul><p><strong>Кое от следните нарушения е възможно при пациенти с тромбофилия?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Вроден или придобит дефицит на Антитромбин (АТIII)</li><li>Дефицит на Протеин С (РС)</li><li>Дефицит на Протеин S (PS)</li><li>Повишен Хомоцистеин</li></ul></ul><p><strong>Посредством кой от изброените по-долу лабораторни тестове не се осъществява контрол на лечението с Хепарин?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">РТ</span></li><li>АРТТ</li><li>Определяне на анти-Ха активност (<span style=\"color: rgb(0, 176, 80)\">особено важен за проследяване на лечение при нискомолекулни хепарини</span>)</li><li>Директно определяне на хепариновата концентрация</li></ul><p><strong>Пациент постъпва в спешно отделение и от рутинните параметри на хемостазата се установяват удължено РТ, удължено АРТТ, намален Фибриноген, намален брой тромбоцити и положителен тест за d-димери. Най-вероятната диагноза е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ДИК синдром</span></li><li>Хемофилия А/Хемофилия В</li><li>Афибриногенемия</li><li>Болест на von Willebrand</li><li>вит К дефицит</li></ul><p><strong>За тромбоцитите е вярно всичко от изброените по-долу, с изключение на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Конвертират фибриногенa във фибрин</span></li><li>Адхезират към увредени съдови стени</li><li>Оказват влияние върху процеса на вазоконстрикция (<span style=\"color: rgb(0, 176, 80)\">отделят серотонин и тромбоксан А2</span>)</li><li>Осигуряват повърхност за осъществяване на процеса на кръвосъсирване</li><li>Освобождават вещества, които неутрализират хепарина (<span style=\"color: rgb(0, 176, 80)\">отделят тромбоцитен фактор 4, който неутралзира хепарина</span>)</li></ul><p><strong>С кое от изброените по-долу състояния се свързва дефект в броя или функцията на тромбоцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Епистаксис</span>&nbsp;<p>(<span style=\"color: rgb(0, 176, 80)\">лигавични/повърхностни кръвоизливи са характерни за нарушена първична хемостаза</span>)</p></li><li>Хемартрози</li><li>Кръвоизливи от меки тъкани</li><li>Удължено АРТТ</li><li>Нормално време на кървене</li></ul><p><strong>Какво би обяснило петехиите по кожа и лигавици на пациент с нормални стойности за РТ, АРТТ, брой на тромбоцитите и време на кървене:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Скорбут</span></li><li>Болест на von Willebrand (<span style=\"color: rgb(0, 176, 80)\">vWF нарушава първичната хемостаза, но и увеличава APTT поради дефицит на фVIII</span>)</li><li>Уремия</li><li>Поглъщане на аспирин</li><li>Хроничен алкохолизъм (<span style=\"color: rgb(0, 176, 80)\">тука става дума за цироза</span>)</li></ul><p><strong>Недостигът на кой от следните изброени протеини е свързан с повтарящо се тромботично разстройство?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Антитромбин III</span></li><li>α-2-макроглобулин</li><li>Фибриноген</li><li>α-2-антиплазмин</li></ul><p><strong>Кое от следните твърдения относно ДИК е вярно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Може да бъде резултат от увреждане на ендотелните клетки</span></li><li>Тромбозата е по-често от кървенето</li><li>Налице е повишаване нивата на фактор VІІІ</li><li>Протромбиновото време е нормално</li><li>Фибриногенът се увеличава</li></ul><p><strong>Кой от следните лабораторни тестове най-добре различава чернодробната коагулопатия от ДИК синдром?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">D-димер</span></li><li>Протромбиново време</li><li>Брой на тромбоцитите</li><li>АРТТ</li><li>Анализ на фактор XIII</li></ul><p><strong>С кое от следните лабораторни изследвания са свързани кръвоизливите в ставите при 18-годишен мъж?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Недостиг на фактор VIII </span>(<span style=\"color: rgb(0, 176, 80)\">млад мъж</span>)</li><li>Недостиг на фактор V</li><li>Удължено РТ два пъти над нормата за здрави</li><li>Положителен тест за Д-димери</li><li>Брой на тромбоцитите 100х10<sup>9</sup>/l</li></ul><p><strong>Кой от следните дефицити е свързан най-често с кървене:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Недостиг на фактор IX</span></li><li>Лупусни антикоагуланти&nbsp;<p>(<span style=\"color: rgb(0, 176, 80)\">води до тромбози, това е АТ, а не реален антикоагулант</span>)</p></li><li>Недостиг на фактор XII</li><li>Дефицит на прекаликреин (<span style=\"color: rgb(0, 176, 80)\">това + фактор XII, характерното за тях е, че силно увеличава APTT, но клинично не са значими</span>)</li><li>Дефицит на Протеин С (<span style=\"color: rgb(0, 176, 80)\">води до тромбофилия</span>)</li></ul><p><strong>30-годишен мъж съобщава за прекомерно кървене след изваждане на зъб. От анамнезата е установено, че майката на пациента е имала менорагия, а сестра му често кървене от носа. При направа на съответните лабораторните изследвания се установява, че пациентът има нормален брой тромбоцити, нормални стойности за РТ и АРТТ. Коя от следните диагнози трябва да се счита за най-вероятна?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Болест на von Willebrand </span>(<span style=\"color: rgb(0, 176, 80)\">кървенето е с характеристика на нарушена първична хемостаза</span>)</li><li>Дефицит на Антитромбин III</li><li>Недостиг на витамин К</li><li>Хемофилия В</li><li>Дефицит на Протеин S</li></ul><p><strong>Коe от следните нарушения НЕ е свързанo с изолирано удължаване на АРТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Недостиг на фактор VII</span></li><li>Терапия с хепарин</li><li>Лупусни антикоагуланти</li><li>Недостиг на фактор IX</li><li>Тежка болест на von Willebrand</li></ul><p><strong>Изолирано удължаване на протромбиновото време (PT) най-вероятно се дължи на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Недостиг на фактор VII</span></li><li>Миелопролиферативно разстройство</li><li>Болест на von Willebrand</li><li>Анормална фибринолиза</li><li>Недостиг на фактор VIII</li></ul><p><strong>Удълженото протромбиново време (РТ) се свързва с всяко от по-долу изброените с изключения на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Болест на von Willebrand</span></li><li>Тежка чернодробна недостатъчност</li><li>Терапия с Варфарин (Синтром)</li><li>Недостиг на витамин К</li><li>Недостиг на фактор VII</li></ul><p><strong>Ако плазма на пациент с абнормно удължено протромбиново време (РТ) или АРТТ се смеси в съотношение 1:1 с нормална плазма и тестът след това НЕ се нормализира, най-вероятната причина за абнормния резултат е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Наличие на инхибитори на кръвосъсирването </span>(<span style=\"color: rgb(0, 176, 80)\">то и да смесиш с нормална плазма, като има инхибитор няя се промени | докато при другите имаш дефицит, който ще се оправи</span>)</li><li>ДИК</li><li>Дефицит на Антитромбин III</li><li>Недостиг на витамин К</li><li>Хемофилия А или В</li></ul><p><strong>Изолирано удължаване на АРТТ може да се дължи на всяко от изброените по-долу, с изключение на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ДИК синдром</span></li><li>Терапия с хепарин</li><li>Лупусни антикоагуланти</li><li>Болест на von Willebrand</li><li>Недостиг на фактор IX</li></ul><p><strong>Кое от изброените по-долу състояния НЕ е свързано с повтарящи се тромбози?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Дефицит на високомолекулен Кининоген&nbsp;</span><p><span style=\"color: rgb(0, 176, 80)\">(HMWK води до увеличаване на APTT, но без реално клинично значение</span>)</p></li><li>Дефицит на Протеин С</li><li>Повишен Хомоцистеин</li><li>Дефицит на Антитромбин III</li><li>Дефицит на Протеин S</li></ul><p><strong>54-годишна жена развива дълбока венозна тромбоза на долните крайници, усложнена от белодробна тромбоемболия. Най-добрата начална терапия е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хепарин</span></li><li>Варфарин (Синтром)</li><li>Аспирин</li><li>Фибринолитично средство (<span style=\"color: rgb(0, 176, 80)\">това е само в много спешни случаи, като при БТЕ където пациента с шок и признаци на оста ДСН</span>)</li><li>Преднизолон</li></ul><p><strong>Пациент с наследствено нарушение на кървенето в крайна сметка е диагностициран с Хемофилия А, посредством коя от следните лабораторни констелации?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Нормално PT, удължено АPTT, нисък фактор VIII, нормален vWF</span></li><li>Удължено PT, нормално АРТТ, нисък фактор VIII, намален vWF</li><li>Удължено PT, удължено АPTT, нисък фактор VIII, нормален vWF</li><li>Нормално РТ, удължено АРТТ, нисък фактор IX, нормален vWF</li><li>Нормално PT, удължено АPTT, нормален фактор VIII, намален vWF</li></ul><p><strong>Всички от изброените по-долу са важни фактори за определяне при Анамнезата на пациента, в опит да се установи дали тромботичното събитие се дължи на дефект в коагулацията, освен:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Атеросклеротични усложнения</span></li><li>Възраст на пациента при първия инцидент</li><li>Семейна история</li><li>Брой на тромботичните събития</li><li>Наличие на злокачествено заболяване</li></ul><p><strong>Кои от посочените фактори са витамин К зависими?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">II, VII, IX, X</span></li><li>I, III, V, VIII</li><li>I, XI, XII, XIII</li><li>III, V, XI, XII</li></ul><p><strong>Кое твърдение е вярно? Нежелани последици от хепариновата терапия са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Хепарининдуцирана тромбоцитопения</li><li>Феномен на възвратно висока съсирваемост</li><li>Хепаринова резистентност</li></ul></ul><p><strong>Пресяващи методи за изследване на хемостаза са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>PT</li><li>фибриноген</li><li>aPTT</li></ul></ul><p><strong>Функцията на фосфолипидите в процеса на коагулация е:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></li><ul><li>Осигуряват каталитична повърхност&nbsp;<p>в процеса на активиране на коагулационните фактори</p></li><li>О<p>граничават коагулационният процес единствено върху тромбоцитния агрегат, т.е. върху съдовата увреда</p></li><li>В<p>одят до локално повишение на концентрацията на коагулационните фактори и улесняват тяхното взаимодействие</p></li></ul></ul><p><strong>Посочете кой е правилният отговор според класическата концепция за коагулацията:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Външният път се активира от тъканния тромбопластин </span>(<span style=\"color: rgb(0, 176, 80)\">това е друго име на тъканен фактор</span>)</li><li>Вътрешният път е по-бърз от външния</li><li>При вътрешния път се образува по-малко количество тромбин</li><li>Външният път не е ефективен за образуване на бърза „запушалка“</li></ul><p><strong>От какво зависи АРТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">От коагулационните фактори на вътрешния и общия път</span></li><li>От коагулационните фактори на външния и общия път</li><li>Само от коагулационните фактори на общия път</li><li>Само от коагулационните фактори на външния път</li></ul><p><strong>Кой от посочените отговори е недостатък на витамин К антагонистите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></li><ul><li>Риск от тромбоза</li><li>Риск от кървене</li><li>Изискват интензивно мониториране</li></ul></ul><p><strong>Антитромбин III действа инактивиращо на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">IIa, IXa, Xa, XIa</span></li><li>Va, VIIIa</li><li>Protein C</li><li>Всички</li></ul><p><strong>Понижени стойности на Protein C могат да се наблюдават при всички изброени ОСВЕН:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лечение с хепарин</span> (<span style=\"color: rgb(0, 176, 80)\">хепаринът не засяга синтеза на Protein C, за разлика от Варфарина</span>)</li><li>Вродено състояние</li><li>ДИК синдром</li><li>Лечение с Warfarin</li></ul><p><strong>Кой микроелемент не се изследва в плазма с Heparin?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Li+</span></li><li>Na+</li><li>Ca2+</li><li>K+</li></ul><p><strong>Кои от изброените процеси са свързани с вторичната хемостаза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">всички са верни</span></li><ul><li>коагулация</li><li>превръщане на хлабавия тромб в здрав</li><li>превръщане на разтворимия белтък фибриноген в неразтворим фибрин</li></ul></ul><p><strong>Кой от изброените не е естествен инхибитор на хемостазата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">тромбин</span></li><li>антитромбин</li><li>протеин C</li><li>хепаринов кофактор 2</li></ul><p><strong>От какво зависи ТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">от коагулационните фактори на общия път</span></li><li>от коагулационните фактори на външния и общ път</li><li>от коагулационните фактори на вътрешния и общ път</li><li>нито едно от изброените</li></ul><p><strong>С кой показател се следи за контрол на терапия с индиректни антикоагуланти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">протромбиново време (INR)</span></li><li>HGB</li><li>aPPT</li><li>левкоцити</li></ul><p><strong>С кой показател се следи за контрол на терапия с директни антикоагуланти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">aPPT</span></li><li>вит. К</li><li>протромбиново време</li><li>HGB</li></ul><p><strong>Кое от следните твърдения за INR и aPPT е вярно?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">те са параметри за лабораторен контрол на антикоагулантна терапия</span></li><li>те са показатели за предстоящо кървене</li><li>те са показатели за успешна терапия</li><li>използват се за терапия на ОМЛ</li></ul><p><strong>Кой път на съсирване отчита протромбиновото време?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">външен път</span></li><li>вътрешен път</li><li>и двата</li><li>нито един</li></ul><p><strong>Кое е грешно за кръвовземането при изследване на протромбиновото време?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">взема се артериална кръв</span></li><li>взема се точно определено количество</li><li>използва се вакутейнер с натриев цитрат</li><li>използва се широка игла</li></ul><p><strong>При терапия с кой от изброените антикоагуланти не е нужен лабораторен контрол?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фраксипарин</span></li><li>Синтром</li><li>Хепарин</li><li>Варфарин</li></ul><p><strong>Какви са терапевтичните стойности на INR при пациенти с клапна протеза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">3.0 – 4.5</span></li><li>1.0 – 2.0</li><li>2.0 - 2.5</li><li>1.5 – 2.5</li></ul><p><strong>Кое не е показателно за повишено кръвосъсирване на пациента (без лаборатория)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">бледост на кожата</span></li><li>кървене от венците</li><li>хематурия</li><li>хематоми</li></ul><p><strong>При дефицит на кой от изброените фактори PT и aPTT ще са в референтни граници:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">XIII</span> (<span style=\"color: rgb(0, 176, 80)\">той е късно, чак в общата система</span>)</li><li>IX</li><li>VII</li><li>VIII</li></ul><p><strong>За нормално протромбиново време се изискват адекватни концентрации на всички изброени фактори, С ИЗКЛЮЧЕНИЕ НА:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фактор VIII</span></li><li>Фактор I</li><li>Фактор V</li><li>Фактор VII</li></ul><p><strong>Аномалиите на фибриногена се откриват чрез кой тест?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тромбиново време</span></li><li>APTT</li><li>PT</li><li>Време на кървене</li></ul><p><strong>INR обикновено се използва за мониторинг на пациенти на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Терапия с Варфарин или подобни орални антикоагуланти</span></li><li>Хепарин</li><li>Клопидогрел</li><li>Аспирин</li></ul><p><strong>Кое от следните се случва при ДИК?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Активиране на фибринолитичната система</li><li>Тромбоцитопения</li><li>Повишено производство на FDP (фибрин-деградационни продукти)</li><li>Консумация на коагулационни фактори</li></ul></ul><p><strong>Какъв е дефектът при резистентност към активиран протеин С?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Дефектна молекула на Фактор V </span>(<span style=\"color: rgb(0, 176, 80)\">Factor V Leiden</span>)</li><li>Дефектна молекула на Протеин S</li><li>Дефектно активиране на Протеин С</li><li>Дефектна молекула на Фактор VIII</li></ul><p><strong>32 годишен мъж с епистаксис има следните резултати: време на кървене &gt; 15 мин., тромбоцитен брой - 230х10<sup>9</sup>g/L, PT и aPTT са в норма. Какво изследване са препоръчали?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">изсл</span><span style=\"color: rgb(255, 0, 0)\">едване агрегация на тромбоцитите </span>(<span style=\"color: rgb(0, 176, 80)\">изследване на първична хемостаза →&nbsp;<p>дефектен или дефицитен GpIIb/IIIa → Glanzmann thrombasthenia</p></span>)</li><li>изследване на костен мозък (<span style=\"color: rgb(0, 176, 80)\">прави се при тромбоцитопения</span>)</li><li>изследване активността на фактор VIII</li><li>преливане на плазма и контрол на времето на кървене</li></ul><p><strong>Защо е необходимо резултати от изследването на PT да се изразяват като INR?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">за да се уеднаквят стойностите в различните лаборатории, работещи с различни реактиви за определяне на PT</span></li><li>за да се мониторират по лесно резултатите на пациентите, лекувани с хепарин</li><li>за да се мониторират по лесно резултатите на пациентите, лекувани с директно тромбинови инхибитори</li><li>за да се уеднаквят стойностите на PT и аPTT</li><li>за да се мониторират по лесно резултатите на пациенти, лекувани с варфаринова терапия</li></ul><p><strong>В какво се измерва функционалната активност на коагулационните фактори?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">проценти (%)</span></li><li>грам на литър (g/l)</li><li>секунди</li><li>всички изброени</li></ul><p><strong>Бременност, след хирургична интервенция, остра инфекция и пациенти в състояние на хиперкоагулация (като тромбоза) са причини за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишен фибриноген</span></li><li>Понижен фибриноген</li><li>Фибриноген в референтни граници</li><li>Всички изброени</li></ul><p><strong>Кое от следните твърдения е ВЯРНО за хемофилията?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Удължено активирано парциално тромбопластиново време</span></li><li>Удължено протромбиново време </li><li>Удължено тромбиново време</li><li>Нивото на фактор на фон Вилебранд в плазмата е понижено</li></ul><p><strong>Дефицитът на кой единичен фактор е вероятен, когато резултатът за PT е удължен, а резултатът за APTT е нормален?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фактор VII</span></li><li>Фактор V</li><li>Фактор VIII</li><li>Протромбин</li></ul><p><strong>Кой тест се използва най-често за мониторинг на терапията с нефракциониран хепарин в централната лаборатория?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">APTT</span></li><li>PT</li><li>TT</li><li>Хромогенен анти-Xa тест (<span style=\"color: rgb(0, 176, 80)\">най-точен, но по-скъп</span>)</li></ul><p><strong>Всички следните изследвания се очакват при ДИК, С ИЗКЛЮЧЕНИЕ НА:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Повишен фибриноген</span></li><li>Тромбоцитопения</li><li>Удължено PT</li><li>Удължено APTT</li><li>Повишен D-димер</li></ul><p><strong>Кое е най-важното приложение на количествения D-димер тест?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Изключване на дълбока венозна тромбоза</span></li><li>Диагноза на остър миокарден инфаркт</li><li>Диагноза на чернодробно и бъбречно заболяване</li><li>Диагноза на първична фибринолиза</li></ul><p><strong>Пациент с рецидивираща тромбоза трябва да бъде изследван за:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Дефицит на Антитромбин III </span></li><li>Дефицит на Фактор VIII</li><li>Хипохомоцистеинемия </li><li>Излишък на Протеин C/S</li></ul><p><strong>Скрининговите тестове за нарушения на вторичната хемостаза са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">PT, APTT, концентрация на фибриноген, TCT</span></li><li>PT, APTT, тромбоцитна агрегометрия</li><li>PT, APTT, тромбоеластография</li><li>APTT, фибриноген, време на кървене, TT</li><li>PT, APTT, фибриноген, време на кървене</li></ul><p><strong>PT измерва .........път. APTT измерва........път.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Външния и общия; вътрешния и общия</span></li><li>Външния; вътрешния и общия</li><li>Общия; вътрешния</li><li>Вътрешния; външния</li></ul><p><strong>Кое от следните твърдения НЕ Е ВЯРНО относно стабилизирането на тромбоцитната запушалка от фибрин? След съдово увреждане, образуването на външна X-аза (VIIa, TF, PL и Ca2+) инициира коагулационната каскада:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Включването на плазминоген и tPA помага за стабилизирането на съсирека</span></li><li>Тромбинът, генериран на мястото на нараняването, превръща разтворимия плазмен фибриноген във фибрин</li><li>Тромбоцитната агрегация и реакциите на освобождаване ускоряват процеса на коагулация, осигурявайки изобилие от мембранни фосфолипиди</li></ul><p><strong>Кое от следните твърдения е ВЯРНО по отношение на фибринолизата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">tPA се освобождава след стимули като травма или физическо натоварване</span></li><li>Плазминогенът е ключов протеин и се активира след превръщане в тъканен плазминогенен активатор </li><li>Фибринолизата е системна, а не локализирана в съсирека</li><li>Фибринолитичните агенти са твърде мощни, за да позволят терапевтичната им употреба</li></ul><p><strong>Тежката хемофилия обикновено се свързва с какъв процент фактор VIII в плазмата?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">По-малко от 1%</span></li><li>2–5%</li><li>6–10%</li><li>50%</li></ul><p><strong>Кое от следните НЕ Е призната причина за ДИК?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Следоперативен режим на легло</span></li><li>Емболия с околоплодна течност</li><li>Менингококов сепсис</li><li>Консумативна коагулопатия, индуцирана от змийска отрова</li></ul><p><strong>Протромбиновото време (PT) може да се използва за откриване или оценка на кое от следните?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Циркулиращ инхибитор срещу Фактор X</span></li><li>Дефицит на контактен фактор</li><li>Дефицит на PF3 (тромбоцитен фактор 3)</li><li>Терапия с нискомолекулярен хепарин</li></ul><p><strong>Кой от следните коагулационни фактори се инхибира от Антитромбин III?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фактор Xa</span></li><li>Фактор V</li><li>Фактор VIII</li><li>Фактор XIII</li></ul><p><strong>Инхибиторът на пътя на тъканния фактор (TFPI) директно инхибира кои съсирващи фактори?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фактор VIIa и Фактор Xa</span></li><li>Фактор V и Фактор II</li><li>Фактор VIII и Фактор IXa</li><li>Фактор XIa и Фактор XIIa</li></ul><p><strong>Кое от следните се случва при първична фибринолиза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></li><ul><li>Повишено образуване на плазмин</li><li>Понижени нива на коагулационни фактори</li><li>Повишено разграждане на фибриноген</li></ul></ul><p><strong>Кой от следните е екзогенен активатор на плазминогена?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Рекомбинантен tPA</span> </li><li>Протеин С</li><li>Фактор XII</li><li>Каликреин</li></ul><p><strong>Пациентка с менорагия е изследвана за APTT, PT, фибриноген и брой тромбоцити. Резултатите показват: удължено APTT, нормално PT, нормален фибриноген и нормален брой тромбоцити. Тези находки са най-съвместими с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Дефицит на Фактор XI </span>(<span style=\"color: rgb(0, 176, 80)\">жена е, тъй че хемофилия супер трудно&nbsp;<p>+ това е хемофилия C, която е и при двата пола</p></span>)</li><li>Предозиране с Варфарин</li><li>Хемофилия B</li><li>Хемофилия A</li></ul><p><strong>3-годишно момче е представено с продължително кървене след циркумцизия (обрязване). Пациентът е изследван за APTT, PT, TT и брой тромбоцити. Резултатите показват: удължено APTT, удължено PT, удължено тромбиново време и нормален брой тромбоцити. Тези находки са най-съвместими с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Тежък дефицит на Фактор I</span><span style=\"color: rgb(0, 176, 80)\"> </span>(<span style=\"color: rgb(0, 176, 80)\">фибриноген</span>)</li><li>Хемофилия А</li><li>Хемофилия B</li><li>ДИК</li></ul><p><strong>Повишеното ниво на кой показател от фибринолитичната система е свързано с риск от артериална тромбоза?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">PAI-1 </span>(<span style=\"color: rgb(0, 176, 80)\">Инхибитор на плазминогенния активатор-1</span>)</li><li>Липопротеин (а)</li><li>Фактор VIIa</li><li>Фактор XII</li></ul><p><strong>Кой ДНК-базиран тест може да се използва за потвърждаване на APC резистентност?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">FVL </span></li><li>Протромбин G20210A</li><li>MTHFR 1298</li><li>MTHFR 677</li></ul><p><strong>Кой терапевтичен агент може понякога да причини ДИК?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Активиран протромбинов комплексен концентрат</span></li><li>Фактор VIII</li><li>Фактор VIIa</li><li>Антитромбинов концентрат</li></ul><p><strong>Пациентът има дълбока венозна тромбоза. APTT е удължено и не се коригира при незабавно смесване на плазмата на пациента с равна част нормална плазма. Какво е предполагаемото състояние?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лупусен антикоагулант </span></li><li>Инхибитор на Фактор VIII</li><li>Дефицит на Фактор VIII</li><li>Фактор V Лайден мутация</li></ul><p><strong>Какво представлява тромбофилията?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Предразположение към тромбоза вследствие на вродено или придобито разстройство</span></li><li>Неподходящо активиране на плазмената коагулационна система</li><li>Състояние, при което съсиреците се образуват неконтролируемо</li><li>Неадекватна фибринолиза</li></ul><p><strong>Кой придобит рисков фактор за тромбоза се оценява в хемостазеологичната лаборатория?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лупусен антикоагулант</span></li><li>Тютюнопушене</li><li>Имобилизация </li><li>Индекс на телесна маса</li></ul><p><strong>Кой лабораторен тест може да се използва за проследяване на терапията с директни тромбинови инхибитори, когато резултатите от APTT са ненадеждни?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">ECT </span></li><li>PT</li><li>Време на рептилаза </li><li>Хромогенен анти-фактор Xa хепаринов анализ</li></ul><p><strong>Кое от следните твърдения е ГРЕШНО относно INR?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">INR се използва за мониториране на терапията с хепарин</span></li><li>INR се изчислява чрез съотношението на PT, повдигнато на степен стойността на ISI</li><li>Желаното INR за пациент на варфарин е между 2.0 и 2.5, но може да бъде и по-високо</li><li>СЗО препоръчва отчитане на INR при пациенти на дългосрочна орална антикоагулантна терапия</li></ul><p><strong>За пациент с нарушение в кръвосъсирването са получени следните лабораторни резултати: Тромбоцитна адхезивност – нормална; PT – удължено; aPTT – нормално; Време на кървене – удължено; Фибриноген – повишен. Тези констатации са най-съвместими с:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Дефицит на Фактор VII</span> </li><li>Лупусен антикоагулант </li><li>Дефицит на Фактор VIII</li><li>Болест на Вилебранд </li></ul><p><strong>С какви методи се изследва активността на коагулационните фактори?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">физиологични методи</span> (<span style=\"color: rgb(0, 176, 80)\">това е активност</span>)</li><li>молекулни методи </li><li>имунологични методи (<span style=\"color: rgb(0, 176, 80)\">това е концентрация</span>)</li><li>всички изброени</li></ul><p><strong>Колко дни са нужни за пълното узряване на тромбоцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">10 дни</span></li><li>2 дни</li><li>30 дни</li><li>120 дни</li></ul><p><strong>При тромболитична терапия 4 часа след началото и два пъти на ден след това трябва да се проследяват следните параметри:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всички</span></li><ul><li>TT</li><li>APTT</li><li>Уринен анализ</li></ul></ul><p><strong>Посочете вярно или грешно е следното твърдение: Ако се взема проба кръв единствено за хемостаза, тя трябва да бъде предшествана от вземане на около 2 мл кръв в друга допълнителна епруветка, която не се използва за анализа.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Вярно</span> (<span style=\"color: rgb(0, 176, 80)\">за да се отстрани тъканния фактор от убождането</span>)</li><li>Грешно</li></ul><p><strong>Към клиничните показания за измерване активността на фIX се отнасят:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Хемофилия В</span></li></ul><p><strong>Критичните стойности на тромбоцитите са:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">&lt; 30х10<sup>9</sup>/L и &gt; 1000x10<sup>9</sup>/L</span></li></ul><p><strong>За изследване на рутинните хемостазеологични параметри се използват:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Цитратна плазма</span></li></ul><p><strong>Потискането на витамин К-редуктазата:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Се осъществява от орални антикоагуланти (Синтром) и се контролира с PT/INR</span></li></ul><p><strong>На кой тест се базира международното нормализирано отношение (INR)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Протромбиново време (PT)</span></li></ul><p><strong>Подредете в правилен ред етапите на първичната хемостаза.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1. Съдова увреда;</span></li><li><span style=\"color: rgb(255, 0, 0)\">2. Съдов спазъм;</span></li><li><span style=\"color: rgb(255, 0, 0)\">3. Тромбоцитна адхезия;</span></li><li><span style=\"color: rgb(255, 0, 0)\">4. Тромбоцитно активиране;</span></li><li><span style=\"color: rgb(255, 0, 0)\">5. Тромбоцитна агрегация.</span></li></ul><p><strong>Посочете 4 индикации за приложение на вит.К антагонисти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">1. Венозни тромбози;</span></li><li><span style=\"color: rgb(255, 0, 0)\">2. Белодробен тромбемболизъм;</span></li><li><span style=\"color: rgb(255, 0, 0)\">3. Мозъчен инсулт;</span></li><li><span style=\"color: rgb(255, 0, 0)\">4. Повтарящи се ОМИ.</span></li></ul><p><strong>Посочете НЕВЯРНОТО твърдение по отношение на фибринолизата:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Фибринолизата е процес на формиране на разтворим фибрин от фибриноген</span></li></ul><p><strong>Кое изследване отразява функционалната активност на тромбоцитите?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Агрегометрия</span></li></ul><p><strong>При кои състояния се наблюдават увеличени нива на Д-димери?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span> (тромбози, ДИК синдром, белодробна емболия и др.)</li></ul><p><strong>Кога е необходимо изследване на фактор IX?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">При проверка/диференциация на дефицити, свързани с фактор VIII</span></li></ul><p><strong>Какви са референтните стойности за броя на тромбоцитите в периферната кръв?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">150 – 400 x 10<sup>9</sup>/L</span></li></ul><p><strong>При какво състояние стойността на аРТТ може да надвиши референтната граница над 2.5 пъти?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Лечение с нефракциониран хепарин</span></li></ul><p><strong>Кой антикоагулант се използва за изследване на коагулационния статус (коагулограма)?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Натриев цитрат</span></li></ul><p><strong>Кой лабораторен показател НЕ е функционално свързан с изследването на аРТТ?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Протромбиново време</span></li></ul><p><strong>Факторът на Hageman (фактор XII) принадлежи към групата на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Контактните ензими</span></li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h2>Още рандъм въпроси</h2><p><strong>Цитологични критерии за микролимфобластна форма на острите лимфобластни левкози:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Малки клетки, хомогенна популация, правилна форма на ядрата</span></li><li>Големи клетки, хетерогенна популация, неправилна форма на ядрата</li><li>Големи клетки, хомогенна популация, фино гранулиран хроматин</li></ul><p><strong>Цитологични критерии за макролимфобластна форма на острите лимфобластни левкози:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Големи клетки, хетерогенна популация, неправилна форма на ядрата</span></li><li>Малки клетки, хомогенна популация, правилна форма на ядрата</li><li>Големи клетки, хомогенна популация, фино гранулиран хроматин</li></ul><p><strong>Цитологични критерии за Бъркитов тип на острите лимфобластни левкози:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\">Големи клетки, хомогенна популация, фино гранулиран хроматин</span></li><li>Големи клетки, хетерогенна популация, неправилна форма на ядрата</li><li>Малки клетки, хомогенна популация, правилна форма на ядрата</li></ul><p><strong>В следното определение попълнете празното място с буква, отразяваща верния термин. Понятието отразява.................броя на разтворените частици в литър разтвор.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><p>осмола<strong>р</strong>итет</p><br></span></li><li>осмола<strong>л</strong>итет</li><li>осмотично налягане</li><li>осмоза</li></ul><p><strong>Кое твърдение по отношение на аполипопротеините В е НЕВЯРНО:</strong></p><ul><li>Прицелните серумни нива са над 1.1 г/л</li></ul><p><strong>За какво служат пробите на Фолхард?</strong></p><ul><li>изследване на концентрационната и разредителната способност на бъбреците</li><li>изследване на протеинурия</li><li>определяне на глюкозен праг</li><li>диагностика на инфекции на пикочните пътища</li></ul><p><strong>Кое твърдение за ЛДХ (LDH) е вярно?</strong></p><ul><li>има 5 изоензимни форми и е неспецифичен маркер за клетъчна деструкция</li><li>специфичен маркер е само за черен дроб</li><li>намалява при инфаркт на миокарда</li><li>изследва се само в урина</li></ul><p><strong>Кой показател се използва за количествено определяне на албуминурията?</strong></p><ul><li>Albumin-Creatinine Ratio (ACR)</li><li>относително тегло на урината</li><li>седимент на урината</li><li>глюкозен толеранс</li></ul><p><strong>Как се класифицира състояние, при което на 0 мин глюкозата е 6.1 - 7.0 mmol/l, а на 120 мин е &lt; 11.1 mmol/l при ОГТТ?</strong></p><ul><li>нарушен глюкозен толеранс (ИГТ)</li><li>захарен диабет тип 2</li><li>здраве (нормален толеранс)</li><li>бъбречен диабет</li></ul><p><strong>С какви средства се провежда лечението при захарен диабет тип 1?</strong></p><ul><li>инсулинови препарати</li><li>орални антидиабетни средства</li><li>диета и спорт (като единствено средство)</li><li>всички изброени</li></ul><p><strong>В кой от изброените случаи урината може да бъде оцветена в червено?</strong></p><ul><li>наличие на миоглобин (миоглобинурия)</li><li>наличие на глюкоза</li><li>наличие на жлъчни пигменти</li><li>наличие на кетони</li></ul><p><strong>При кое състояние, освен бъбречни заболявания, се наблюдава повишен креатинин?</strong></p><ul><li>мускулна дистрофия</li><li>захарен диабет</li><li>грип</li><li>хипертония</li></ul><p><strong>Физиологично повишени стойности на холестерол се установяват при:</strong></p><ul><li>бременност</li><li>детска възраст</li><li>малабсорбционен синдром</li><li>тиреотоксикоза</li><li>липсва верен отговор</li></ul><p><strong>Повишени стойности на холестерол (хиперхолестеролемия), в резултат от вторични нарушения на липидния транспорт се установяват при пациенти с:</strong></p><ul><li>билиарна цироза</li><li>болести „на натрупване“</li><li>хроничен нефрит</li><li>хипотиреоидизъм</li><li>всички изброени</li></ul><p><strong>Повишени стойности на триглицериди (хипертриглицеридемия) се установяват при пациенти с:</strong></p><ul><li>нефрозен синдром</li><li>захарен диабет</li><li>алкохолизъм</li><li>панкреатити</li><li>всички изброени</li></ul><p><strong>Основните изоензими на Креатинкиназата в миокарда са:</strong></p><ul><li>СК-ММ; СК-ВВ</li><li>СК-МВ, СК-ММ</li><li>СК-ММ</li><li>СК-МВ</li><li>СК-ВВ, СК-ММ, СК-МВ</li></ul><p><strong>Кой от изброените по-долу маркери се явява много чувствителен и ранен маркер при ОМИ?</strong></p><ul><li>тропонин</li><li>BNP</li><li>СК-МВ</li><li>карбоанхидраза III</li><li>всички изброени</li></ul><p><strong>Изостенурия е състояние, при което:</strong></p><ul><li>бъбреците са загубили възможността са да концентрират и разреждат урината, а относителната й маса е около 1,010</li></ul><p><strong>При наличие на леки вериги в урината, протеин урията се дължи на:</strong></p><ul><li>Преренални заболявания</li></ul><p><strong>При определянето на Hb с автоматичен анализатор, левкоцитоза &gt;50х10<sup>9</sup>/l, тромбоцитоза &gt;70х10<sup>9</sup>/l, липемия, хипербилирубинемия, хиперпротеинемия:</strong></p><ul><li>са причина за получаване на фалшиво завишени стойности</li></ul><p><strong>Кое от изброените твърдения за MCV</strong></p><ul><li>намалява при чернодробни заболявания</li></ul><p><strong>Сигурна диагноза диабет (ADA) се поставя, когато:</strong></p><ul><li>Глюкозата на гладно е &gt; 7.0 mmol/L</li></ul><p><strong>При какви стойности на екскреция на белтък в урината говорим за патологична протеинурия?</strong></p><ul><li>Над 150 мг/24 часа</li></ul><p><strong>Глюкозурия:</strong></p><ul><li>се появява,когато нивата на серумната глюкоза са над т.нар. бъбречен праг</li></ul><p><strong>Кое от изброените твърдения за пикочната киселина е невярно:</strong></p><ul><li>серумните концентрации се независими от пола</li></ul><p><strong>При индиректна хипербилирубинемия:</strong></p><ul><li>неконюгираният билирубин преминава през кръвномозъчната бариера и се натрупва в мозъчните ядра</li></ul><p><strong>Кои от изброените ензими принадлежи към т.нар. функционални плазмени ензими:</strong></p><ul><li>Плазминоген</li></ul><p><strong>Причини за увеличаване нивата на LDH в кръвта са всички изброени ОСВЕН:</strong></p><ul><li>Заболявания на белия дроб</li></ul><p><strong>Цистатин С</strong></p><ul><li>служи за оценка скоростта на гломерулната илтрация</li></ul><p><strong>К+:</strong></p><ul><li>напуска клетките при ацидоза (хиперкалиемия)</li></ul><p><strong>Коя от изброените буферни системи играе най-съществена роля в кръвта по отношение на регулацията на киселинно-алкалното равновесие:</strong></p><ul><li>бикарбонатен буфер</li></ul><p><strong>При първичен хипертиреоидизъм се установяват:</strong></p><ul><li>Намалени нива на TSH &lt;5 mlU/L</li></ul><p><strong>Калцитонинът:</strong></p><ul><li>е хормон, който се използва най-вече като туморен маркер за медуларен карцином на щитовидната жлеза</li></ul><p><strong>Основен хормон регулиращ нивото на глюкозата е</strong></p><ul><li>инсулин</li><li>адреналин</li><li>кортизол</li></ul><p><strong>Изследването на Пептид С и инсулин при:</strong></p><ul><li>за диагностика на инсулином</li><li>диагноза на диабета</li><li>съмнение за автоимунна генеза на диабета</li></ul><p><strong>Кои тестове се използват за диагноза на Диабет II тип</strong></p><ul><li>ОГТТ и НвА1с</li><li>ниво на холестерол и триглицериди</li><li>кръвна захар на гладно</li><li>урея и креатинин</li></ul><p><strong>Кои тестове са за мониториране и компенсираност на диабета?</strong></p><ul><li>НвА1с</li><li>ОГТТ</li><li>креатинин</li><li>микроалбумин</li></ul><p><strong>Кога се налага изследването на фруктозамина?</strong></p><ul><li>при бременност</li><li>за диагноза</li><li>при мониториране на диабет тип2</li></ul><p><strong>Рутинен метод за определяне на общия белтък е</strong></p><ul><li>Биуретов метод</li><li>нефелометрия</li><li>Метод на Киелдал</li><li>абсорбция в ултравиолетовия спектър</li></ul><p><strong>Повишение на общия белтък има при:</strong></p><ul><li>при миелом</li><li>нефрозен синдром</li><li>след операция</li><li>при чернодробни заболявания</li></ul><p><strong>Избройте няколко метода за фракциониране и определяне на белтъците</strong></p><ul><li>Електрофореза</li><li>Фотометрично</li><li>Имунологични</li><li>Доказване в мекониум при муковисцидоза чрез експресни ленти с тетрабромфенолблау</li></ul><p><strong>М градиентът е:</strong></p><ul><li>увеличение на парапротеини</li><li>увеличаване на албумина</li><li>увеличаване на ЛДЛ холестерола</li><li>увеличение на С реактивния протеин и фибриногена</li></ul><p><strong>Имуноглобулин Е се повишава при:</strong></p><ul><li>при алертии</li><li>при възпаление</li><li>при бъбречни заболявани</li><li>при паразитни заболявания</li></ul><p><strong>С реактивният протеин е лабораторен параметър, който се свързва с:</strong></p><ul><li>бактериални и вирусни инфекции</li><li>рисков фактор за сърдечно съдови заболявания</li><li>нарушения в кръвосъсирването</li><li>бременност</li></ul><p><strong>Показатели за оценка на бъблечната фунция са</strong></p><ul><li>урея, креатинин и пикочна киселина</li><li>глюкоза калий и креатинин</li><li>калций, фосфор и креатинин</li><li>албумин, глюкоза, креатинин</li></ul><p><strong>Креатининовия клирънс служи за оценка на:</strong></p><ul><li>Гломерулната филтрация</li><li>тубулната функция</li><li>бъбречното налягане</li><li>инкреторната функция на бъбрека</li></ul><p><strong>Повишение на уреята се наблюдава при:</strong></p><ul><li>при кръвоизливи в гастро-интестиналния тракт</li><li>чернодробна недостатъчност</li><li>при диабет</li><li>недоимъчно хранене и кахексия</li></ul><p><strong>Подаграта се съпровожда с увеличение на:</strong></p><ul><li>пикочната киселина</li><li>креатинина</li><li>уреята</li><li>калция</li></ul><p><strong>Бъбречната функция се изследва със следните показатели:</strong></p><ul><li>креатинин и урея</li><li>белтък в урината</li><li>пикочна киселина</li><li>амоняк</li></ul><p><strong>Определянето на общия билирубин става с:</strong></p><ul><li>Диацо метод ( диацонирана сулфонилова киселина)</li><li>Биуретов метод</li><li>Метод на Яффе(с пикринова киселина)</li><li>Тест на Варбург</li></ul><p><strong>При новородените до 60 ден се надюдава</strong></p><ul><li>Увеличение наобщия и индиректния билирубин</li><li>намаляване на билирубина</li><li>Увеличение на общия и директния билирубин</li></ul><p><strong>Кои лабораторни параметри се използват за чернодробни заболявания</strong></p><ul><li>билирубин общ и директен</li><li>СРП и хаптоглобин</li><li>глюкоза и пикочна киселина</li><li>уробилиноген в урина</li></ul><p><strong>Кое твърдение за натрия НЕ е вярно?</strong></p><ul><li>концентрацията му в еритроцитите е много висока и се отделя масивно при хемолиза</li><li>той е основен извънклетъчен катион</li><li>регулира осмотичното налягане</li><li>нивата му се контролират от алдостерон</li></ul><p><strong>Каква е диагнозата при понижено TSH и fT4 в референтни граници?</strong></p><ul><li>първичен субклиничен хипертиреоидизъм</li><li>първичен клинично изявен хипертиреоидизъм</li><li>вторичен хипотиреоидизъм</li><li>еутиреоидно състояние</li></ul><p><strong>Високи триглицериди се наблюдават при:</strong></p><ul><li>захарен диабет</li><li>пневмония</li><li>гладуване</li><li>след нахранване</li></ul><p><strong>Кое твърдение за холестерола не е вярно:</strong></p><ul><li>намалява при стрес и бременност</li><li>транспортира се до тъканите в свободно сътояние</li><li>увеичава се при затлъстяване</li><li>високите стойности имат атерогено действие</li></ul><p><strong>При кой тип хиперлипопротеинемия има бистър серум?</strong></p><ul><li>хиперхолестеролемия (тип ІІа)</li><li>хиперхиломикронемия (І тип)</li><li>индуцирана от нахранване хипертриглициридемия (тип V)</li></ul><p><strong>Кое от следните заболявания не е причина за хиперлипопротеинемия</strong></p><ul><li>хронична инфекция</li><li>захарен диабет</li><li>алкохолизъм</li><li>затлъстяване</li></ul><p><strong>Какъв метод се използва за определяне на ХДЛ (HDL)</strong></p><ul><li>преципитационни с полимери ииндиректно пресмятане</li><li>Биуретов метод</li><li>Реакция на Яфе</li><li>имуносепаративни методи</li></ul><p><strong>Кои апопротеини са атерогенни</strong></p><ul><li>апо(а)</li><li>Апо С</li><li>Апо Е2</li></ul><p><strong>Кой ензим е основен в метаболизма на липопротеините</strong></p><ul><li>ЛХАТ (Лецитинхолестеринацилтрансфераза)</li><li>ЛДХ (Лактат дехидрогеназа)</li><li>ЛАП (левцинаминопептидазата)</li><li>ЧТгЛ</li></ul><p><strong>При какв температура се определят ензимите</strong></p><ul><li>37°С</li><li>30°С</li><li>25°С</li><li>при трите</li></ul><p><strong>Кои ензими са с локализация в митохондрии:</strong></p><ul><li>АСАТ, ГЛД, КК</li><li>АЛАТ, АСАТ, ГГТ</li><li>ГЛД, КФ, АФ</li><li>ЛДХ,КК,а-амилаза</li></ul><p><strong>Принципът на Варбург за определяне на ензимна активност почива на принципа</strong></p><ul><li>промяна в поглъщането НАД→НАДН2</li><li>промяна цвета на хромогена</li><li>помътняване на реакционната смес</li><li>инхибиране на някои субединици на ензима.</li></ul><p><strong>АСАТ и АЛАТ рутинно се определят с:</strong></p><ul><li>кинетично-колориметричен метод</li><li>двустъпален колориметричен тест</li><li>тест на Варбург</li><li>имунометричен</li></ul><p><strong>Коя е най-честата причина за патологично увеличение на ГГТ при АСАТ 50 U/l, АЛАТ 58 U/l и ГГТ 998 U/l?</strong></p><ul><li>Алкохолна злоупотреба- чернодробно заболяване</li></ul><p><strong>Какви стойности има отношението АСАТ/АЛАТ при остър вирусен хепатит?</strong></p><ul><li>АсАТ/АлАТ &lt;0,7</li><li>АсАТ/АлАТ &gt;1</li></ul><p><strong>Кое твърдение за АЛАТ не е вярно</strong></p><ul><li>намалените стойности имат важно клинично значение</li><li>увеличава се при остри хепатити</li><li>увеличава се при ОМИ</li><li>намира се в цитоплазмата на клетките</li></ul><p><strong>ГГТ, АФ и ЛАП са харектерни за:</strong></p><ul><li>за холестаза</li><li>за остри вирусни хеатити</li><li>за мускулни заболявания</li><li>за бъбречни заболявания</li></ul><p><strong>Кои ензими са са характерни за костни заболавания и метастази</strong></p><ul><li>АФ, КФ</li><li>ААТ, КФ</li><li>ГГТ, а-амилаза</li></ul><p><strong>Кои езими се използват за диагностика на чернодробни заболявания</strong></p><ul><li>ГГТ, АСАТ, АЛАТ, ГДХ</li><li>АСАТ, АЛАТ, КК, ЛАП</li><li>АФ, ГГТ, а-амилаза, Гл6ФДХ</li><li>КФ, холинестераза, ГГТ, липаза</li></ul><p><strong>Констелация от кои ензимни се използва за диагностика на инфаркт на миокарда.</strong></p><ul><li>КК, КК-МВ, АСАТ, НВДХ</li><li>АЛАТ,АСАТ,КК,ХЕ</li><li>АСАТ, ГГТ, КК-МВ, ЛДХ</li><li>ЛДХ, АСАТ, КК, НВДХ</li></ul><p><strong>Определянето на свободен протеин α1-MiG (алфа-1 микроглобулин) в урината е:</strong></p><ul><li>Лабораторен маркер за тубулна дисфункция</li></ul><p><strong>Повишен риск от развитие на усложнения при болни от захарен диабет има, когато се открие:</strong></p><ul><li>Микроалбумини в урината поне в 2 от 3 проби урина за период от 6 месеца</li></ul><p><strong>Кое твърдение по отношение на биологично активните молекули, секретирани от адипоцитите, е НЕВЯРНО:</strong></p><ul><li>Противогликемично действие имат: лептин и адипонектин</li></ul><p><strong>Кое твърдение за хормона пролактин е вярно:</strong></p><ul><li>При стойности над 100 mlU/ml може да се мисли за тумор на хипофизата</li></ul><p><strong>Коя е основната индикация за изследване на туморни маркери:</strong></p><ul><li>Контрол на ефикасността на дадено лечение и стадиране на болестния процес</li></ul><p><strong>В кой случай НЕ СЕ ВЗЕМА КРЪВ за изследване на PSA:</strong></p><ul><li>След преглед при уролог с ректално туширане</li></ul><p><strong>При изследване на дигоксин в кръвта препоръчителните терапевтични граници са:</strong></p><ul><li>1.0 – 2.6 nmol/l</li></ul><p><strong>Препоръчителни серумни нива на HDL-C са:</strong></p><ul><li>Мъже – над 1.1 mmol/l; Жени – над 1.3 mmol/l</li></ul><p><strong>Какви са референтните стойности на рН на артериалната кръв?</strong></p><ul><li>7.36 – 7.44</li></ul><p><strong>Кой от изброените ензими е най-чувствителен маркер за хепатоцитна увреда (цитолиза)?</strong></p><ul><li>АсАТ (или АЛАТ)</li></ul><p><strong>При отравяне с кой елемент се наблюдават симптоми от страна на ЦНС, преумора и дъх на чесън?</strong></p><ul><li>Селен</li></ul><p><strong>Кои фактори са от съществено значение за контрола на захарния диабет?</strong></p><ul><li>Контрол на кръвната захар, здравословно хранене, спорт и редукция на теглото</li></ul><p><strong>Какво представлява гестационният диабет?</strong></p><ul><li>Появява се по време на бременност</li></ul><p><strong>Кой хормон се секретира от предния дял на хипофизата (аденохипофиза)?</strong></p><ul><li>ТСХ (Тиреостимулиращ хормон)</li></ul><p><strong>Кой хормон участва в растежа и развитието на вторичните полови белези?</strong></p><ul><li>DHEA</li></ul><p><strong>При кое състояние може да се наблюдава повишен креатинин, извън бъбречна недостатъчност?</strong></p><ul><li>Мускулна дистрофия</li></ul><p><strong>Кои други клетъчни редове могат да бъдат засегнати при миелоидна левкемия?</strong></p><ul><li>Еритроидният ред</li></ul><p><strong>При кои патологични състояния се наблюдава повишаване на ензима АсАТ (AST)?</strong></p><ul><li>Всички изброени (сърце, бял дроб, черва и др.)</li></ul><p><strong>Намалението на кой белтък е специфичен маркер за диагностика на болестта на Уилсън?</strong></p><ul><li>Церулоплазмин</li></ul><p><strong>Какво изследваме чрез показателите на КАС?</strong></p><ul><li>Оценява се метаболитният и респираторният статус на организма (pH, pCO2, pO2, бикарбонати)</li></ul><p><strong>При кое заболяване е клинично важно да се определи нивото на пролактин?</strong></p><ul><li>Пролактином</li></ul><p><strong>Кой от изброените хормони е производен на аминокиселината тирозин?</strong></p><ul><li>Тироксин</li></ul><p><strong>Кои азотсъдържащи вещества се намират в кръвта?</strong></p><ul><li>Амоняк, креатинин</li></ul><p><strong>При пациент с астма и променени клинични показатели, каква диагноза се търси?</strong></p><ul><li>Определяне на дихателна (респираторна) алкалоза или ацидоза</li></ul><p><strong>Вярно ли е, че при ранна тромболиза първоначалното увеличение на ензимите се дължи на \"wash out\" феномен?</strong></p><ul><li>Вярно</li></ul><p><strong>При коя интоксикация се наблюдава хиперкалиемия?</strong></p><ul><li>Дигоксинова интоксикация</li></ul><p><strong>При кои състояния се наблюдава хипонатриемия?</strong></p><ul><li>Всички отговори са верни (диария, повръщане, прием на диуретици, фистули)</li></ul><p><strong>Кой вид липопротеини пренася триглицеридите от храната до черния дроб?</strong></p><ul><li>Хиломикрони</li></ul><p><strong>Какво означава терминът \"хилурия\"?</strong></p><ul><li>Наличие на лимфа в урината</li></ul><p><strong>Какви са референтните граници на калия в кръвта?</strong></p><ul><li>3.5 – 5.5 mmol/L</li></ul><p><strong>С какво изследване ще различите адрено-продуциращ тумор на надбъбреците и адрено-продуциращ тумор на яйчниците?</strong></p><ul><li>дехидроепиандростерон сулфат (DHEA-S)</li><li>Естрадиол</li><li>Тестостерон</li><li>Пролактин</li></ul><p><strong>Какво се изследва в урината чрез използването на 20% сулфосалицилова киселина?</strong></p><ul><li>Белтъци</li></ul><p><strong>Кои са основните причини за развитие на хиперхлоридемия?</strong></p><ul><li>Бъбречна тубулна ацидоза, хронична хипервентилация, вливане на хлориди, хипертонична дехидратация, отравяне със салицилати</li></ul><p><strong>Какви са референтните стойности за концентрацията на глюкоза в кръвта?</strong></p><ul><li>2.8 – 5.6 mmol/L</li></ul><p><strong>За какво свидетелства наличието на повишени стойности на нитрити в урината?</strong></p><ul><li>Бактериална инфекция на пикочните пътища</li></ul><p><strong>Кога се наблюдава явлението \"интерференция\" при лабораторните изследвания?</strong></p><ul><li>Всички отговори са верни (при наличие на хемолиза, липемия или иктер)</li></ul><p><strong>Кое твърдение е вярно за ензима АсАТ (AST)?</strong></p><ul><li>Има две изоензимни форми: митохондриална и цитозолна</li></ul><p><strong>Кой е най-подходящият метод за оценка на дългосрочния въглехидратен контрол при пациент с повишена глюкоза на гладно?</strong></p><ul><li>Изследване на гликиран хемоглобин (HbA1c)</li></ul><p><strong>Наличието на кои съставки в урината води до нейното засилено пенене?</strong></p><ul><li>Белтъци и жлъчни пигменти</li></ul><p><strong>Кое твърдение относно изработването на контролна проба НЕ е вярно?</strong></p><ul><li>Изработва се при специални условия (различни от тези на пациента)</li></ul><p><strong>Какъв е полуживотът на албумина в човешкия организъм?</strong></p><ul><li>Около 20 дни</li></ul><p><strong>Кой е антикоагулантът на избор при изследване на pH и кръвни газове?</strong></p><ul><li>Хепарин</li></ul><p><strong>Кое заболяване засяга едновременно еритроидния и миелоидния (белия) кръвен ред?</strong></p><ul><li>Еритролевкемия</li></ul><p><strong>Как се класифицира състоянието при показатели: pH 7.1, pCO2 2.5, BE (бикарбонати) ниски?</strong></p><ul><li>Метаболитна ацидоза</li></ul><p><strong>Кои са характерните симптоми на диабетната кетоацидоза?</strong></p><ul><li>Всички изброени (умора/летаргия, гадене, полидипсия, плодов дъх на ацетон)</li></ul><p><strong>Кой хормон е пряко отговорен за факултативното обратно всмукване на вода в бъбреците?</strong></p><ul><li>Антидиуретичен хормон (АДХ / вазопресин)</li></ul><p><strong>За кое състояние са характерни признаците \"луновидно лице\", стрии и понижени нива на АКТХ?</strong></p><ul><li>Синдром на Кушинг (първичен/адренален произход)</li></ul><p><strong>Коя липопротеинова фракция съответства на пре-бета-фракцията при електрофореза?</strong></p><ul><li>VLDL</li></ul><p><strong>Какво отразява изследването на относителното тегло на урината?</strong></p><ul><li>Концентрационно-разредителната функция на бъбреците</li></ul><p><strong>Кой е най-често изследваният ендогенен показател за очистителната (екскреторна) функция на бъбреците?</strong></p><ul><li>Креатинин</li></ul><p><strong>Кой хормон предизвиква вазоконстрикция и стимулира обратната реабсорбция на вода в бъбреците?</strong></p><ul><li>Вазопресин (Антидиуретичен хормон - АДХ)</li></ul><p><strong>При кой тип хиперлипопротеинемия се наблюдава изолирано повишение на нивата на LDL?</strong></p><ul><li>Тип IIa</li></ul><p><strong>При кое състояние се наблюдава изразена хиперпротеинемия (повишен общ белтък)?</strong></p><ul><li>Макроглобулинемия на Валденщрьом</li></ul><p><strong>При кое от посочените състояния се наблюдава хипопротеинемия?</strong></p><ul><li>Недохранване (маразъм, квашиоркор)</li></ul><p><strong>Кога се наблюдава изолирано повишение на уреята при нормални стойности на креатинина?</strong></p><ul><li>Преренална азотемия (напр. дехидратация) или диета, богата на протеини</li></ul><p><strong>Каква е основната биохимична роля на ензимите АсАТ и АЛАТ?</strong></p><ul><li>Участват в процесите на трансаминиране на аминокиселините</li></ul><p><strong>Заболяванията на кой орган най-често водят до развитие на обструктивен (механичен) иктер?</strong></p><ul><li>Жлъчен мехур и жлъчни пътища</li></ul><p><strong>Кой лабораторен параметър отразява средните нива на кръвната захар за период от няколко седмици (месеци) назад?</strong></p><ul><li>Гликиран хемоглобин (HbA1c)</li></ul><p><strong>Кой хормон води до повишаване на нивата на калция в кръвната плазма?</strong></p><ul><li>Паратхормон (ПТХ)</li></ul><p><strong>Какво представлява състоянието \"хилурия\"?</strong></p><ul><li>Наличие на лимфа в урината</li></ul><p><strong>Каква е средната продължителност на плазмения живот на албумина?</strong></p><ul><li>20 дни</li></ul><p><strong>Какво представляват по своята същност телцата на Папенхайм?</strong></p><ul><li>Интраеритроцитни гранули, съдържащи желязо</li></ul><p><strong>Как може да се разграничи дали пененето на урината се дължи на наличие на белтък?</strong></p><ul><li>Чрез утаяване с 20% сулфосалицилова киселина</li></ul><p><strong>Какви са препоръчителните диетични промени при пациенти с хронично бъбречно заболяване?</strong></p><ul><li>Прием на нормално количество калории при ограничаване на протеиновия внос</li></ul><p><strong>Какви изоензимни форми притежава ензимът АсАТ (AST)?</strong></p><ul><li>Митохондриална и цитоплазмена форма</li></ul><p><strong>Как се променя осмолалитетът на плазмата при състояние на дехидратация?</strong></p><ul><li>Повишава се</li></ul><p><strong>Кои са характерните имунологични и морфологични находки при Множествен миелом?</strong></p><ul><li>Наличие на моноклонален имуноглобулин (М-протеин) и клетки на Mott?</li></ul><p><strong>Кой хормон е отговорен за регулирането на обратната реабсорбция на вода в събирателните каналчета на бъбрека?</strong></p><ul><li>Антидиуретичен хормон (АДХ / Вазопресин)</li></ul><p><strong>Каква е честотата на генетично обусловените (фамилни) липопротеинемии сред населението?</strong></p><ul><li>Около 50% (при определени популации с висок риск)</li></ul><p><strong>Каква промяна в КАС се наблюдава при хипералдостеронизъм?</strong></p><ul><li>Метаболитна алкалоза</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h2>Някакви cases</h2><h4>Case 1</h4><p>25 годишна жена е с оплаквания от менорагия. ОПЛ назначава пресяващи коагулационни тестове. Резултатите показват – тромбоцитопения.</p><ul><li><strong>Каква е най-вероятната причина за оплакванията?</strong> </li><ul><li>Нарушения на съдовата стена</li><li>Нарушения на тромбоцитната функция</li><li>Болест на фон Вилебранд</li><li>Хипо- и афибриногенемия</li><li>Прием на антиагреганти</li></ul><li><strong>Какъв е характерът на кръвоизливите при нарушения в първичната хемостаза?</strong> </li><ul><li>Кожно-лигавични</li><li>Епистаксис</li></ul></ul><h4>Case 2</h4><p>30 годишна жена получава обилен кръвоизлив след екстракция на зъб. Назначени са пресяващи коагулационни тестове. Резултатите от изследванията показват аРТТ над нормата.</p><ul><li><strong>Какви допълнителни изследвания бихте назначили?</strong> </li><ul><li>ТТ (тромбиново време)</li><li>Измерване на индивидуалните фактори на кръвосъсирването</li><li>Измерванена VWF </li><li>Измерване на коагулационните инхибитори </li><li>Измерване на Д-димери</li></ul><li><strong>Каква е най-вероятната причина?</strong></li><ul><li>Болест на фон Вилебранд, Дефицит</li><li>Дефицит на факторите на съсирването (ф-р 7,8) </li><li>ДИК синдром</li><li>Прием на антикоагуланти, аспирин.</li></ul></ul><h4>Case 3</h4><p>2-годишно момче постъпва в СПО по повод на хемартроза в резултат на незначителна травма. Резултатите от проведените изследвания показват, че е повишено аРТТ, а останалите показатели са в референтни граници.</p><ul><li><strong>Какви допълнителни изследвания бихте назначили?</strong></li><ul><li>Изследване на индивидуалните фактори на кръвосъсирване, установяване на налични инхибитори на коагулацията или дефицит на витамин К.</li></ul><li><strong>Каква е най-вероятната причина?</strong></li><ul><li>Дефицит на фактор на вътрешния път на кръвосъсирването – най-вероятно VIII, IX, XI, XII (Детето има хемофилия)</li></ul></ul><h4>Case 4</h4><p>60-годишен мъж с диагноза ПМ, с оглед профилактика на тромбоемболизъм е назначена терапия с Acenocoumarol. Назначените изследвания показват INR под нормата.</p><ul><li><strong>Нуждае ли се пациента от корекция в дозата на пероралния антикоагулант?</strong></li><ul><li>Да</li></ul><li><strong>Какъв е оптималния терапевтичен оптимум на INR?</strong></li><ul><li>2.0 – 3.5</li></ul><li><strong>Необходимо ли е проследяване на аPTT?</strong></li><ul><li>Да, профилактично поне веднъж в месеца</li></ul></ul><h4>Case 5</h4><p>Пациент с ДВТ е приет в съдова хирургия. При постъпването са назначени изследвания. Резултатите сочат, че всички стойности на пациента от изследването след постъпване в отделението са в референтните граници. Назначена е терапия с нефракциониран хепарин в доза- 5000IU болус, последвана от венозна инфузия в доза- 10IU/kg/h. След 6h са назначени изследвания: установявя се повишаване на аPTT – 60 сек при норма 25-40 сек.</p><ul><li><strong>Нуждае ли се пациента от корекция в дозата на хепарина?</strong></li><ul><li>Не</li></ul><li><strong>Какъв е оптималния терапевтичен оптимум за aPTT?</strong></li><ul><li>1.5-2.5</li></ul><li><strong>Какви са възможните усложнения от лечението с хепарин?</strong></li><ul><li>HIT (хепарин индуцирана тромбоцитопения), кървене, остеопороза, повишаване на трансаминази</li></ul><li><strong>Как се преминава към перорален антикоагулант?</strong></li><ul><li>Необходимо е хепаринът и пероралният антикоагулантът да се приемат заедно в рамките на минимум 5 дни, до достигане на терапевтична област на INR. След това се спира хепарина</li></ul></ul><h4>Case 6</h4><p>Бременна с хабитуални аборти (повече от 3 последователни спонтанни аборта). Открити са антифосфолипидни антитела (те активират каскадата на кръвосъсирването, така се повишава риска от образуване на кръвни съсиреци и това води до аборт). Назначен е нискомолекулен хепарин.</p><ul><li><strong>Дали е необходим контрол на НМХ?</strong></li><ul><li>Не е необходим контрол</li></ul><li><strong>При кои пациенти е необходим?</strong></li><ul><li>Деца, възрастни пациенти с големи коремни операции, при бременни</li></ul><li><strong>Кой е тестът, с който се препоръчва мониториране на лечението с НМX?</strong></li><ul><li>Анти Ха измерване. При бременни се отчитат нивата на анти Ха, 4 до 6 часа след въвеждане на НМХ (референтните стойности са 0.8-1.2 U/ml)</li></ul></ul><h4>Case 7</h4><p>Пациент с протезирана тазобедрена става е на лечение с Dabigatran (директен инхибитор на тромбина), с оглед предотвратяване на риска от ДВТ.</p><ul><li><strong>Необходим ли е лабораторен контрол при лечение с директен инхибитор на тромбина – Dabigatran?</strong></li><ul><li>Тъй като има висок риск от кървене, пациентът подлежи на лабораторен контрол на aPTT, TT и ECT (екариново време на съсирване)</li></ul></ul><h4>Case 8</h4><p>1-месечно момче е прието в болница с анамнеза за повръщане и летаргия, които са започнали преди 24 часа. СТ показва голям субдурален хематом. Проведените изследвания показват, че INR &amp; aPTT са над нормата.</p><ul><li><strong>Какви допълнителни изследвания бихте назначили?</strong></li><ul><li>Агрегометрия</li><li>Измерване на активност и концентрация на vWF</li><li>Измерване на индивидуални фактори на кръвосъсирването</li><li>Измерване на инхибитори на кръвосъсирването</li></ul><li><strong>Каква е най-вероятната причина?</strong></li><ul><li>Намалени фактори на кръвосъсирването</li></ul><li><strong>Каква е патогенезата на ХБН (хеморагична болест на новороденото)?</strong></li><ul><li>Дефицит на витамин К (може да е поради незрялост на черния дроб на новороденото, липсата на определени микроорганизми в чревната флора, които участват в синтезата на витамин К, понижен внос на витамин К при кърмене)</li></ul><li><strong>Кои са витамин К-зависимите фактори на кръвосъсирването?</strong></li><ul><li>II, VII, IX, X</li></ul></ul><h4>Case 9</h4><p>Бременна жена е приета в гинекология с хеморагични були, подкожни кръвоизливи и кървене от местата на венозна пункция. Изследванията показват тромбоцитопения, INR &amp; aPTT над нормата и фибриноген под нормата.</p><ul><li><strong>Има ли специфични референтни стойности за D-димер по време на бременност?</strong></li><ul><li>Референтните стойности са ≤ 0,5 mcg/mL, но при бременни стойностите нормално се покачват физиологично</li></ul><li><strong>Каква е най-вероятната причина за състоянието?</strong></li><ul><li>Синдром на дисеминирана интравазална коагулация (ДИК синдром)</li></ul><li><strong>Каква е патогенезата за DIC?</strong></li><ul><li>Директно активиране на протромбина или на фактор X, активиране на външната система на плазмената коагулация от тъканен тромбопластин, контактно активиране на вътрешната система на плазмената коагулация</li></ul><li><strong>Какви други причини за повишен D-димер познавате?</strong></li><ul><li>Венозна тромбоза</li><li>БТЕ</li><li>Артериална тромбоза и емболия</li><li>Тромбофлебит</li><li>Травми/операции</li><li>Изгаряния</li><li>Аортна дисекация</li><li>Сепсис</li><li>Фибринолитична терапия</li><li>Съдови аневризми</li><li>Порто-кавален шънт</li><li>Злокачествени заболявания</li><li>Хемангиом</li></ul></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\">до ~ 90 страница от панвъпросения<br><br><br><br><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
